def _synrov_app_dir() -> Path:
    """Return a writable application folder in script and frozen/exe modes."""
    try:
        if getattr(sys, "frozen", False):
            return Path(sys.executable).resolve().parent
        return Path(__file__).resolve().parent
    except Exception:
        return Path.cwd()


