# Ordered so the combobox lists are deterministic
_COLOR_EN_ORDER: List[str] = ["green", "red", "blue", "yellow", "generic"]


def _color_canonical(value: str) -> str:
    """Always return the English canonical color name (stored form)."""
    s = str(value or "green").strip().lower()
    return _COLOR_PT_TO_EN.get(s, s if s in _COLOR_EN_TO_PT else "green")


def _color_display(canonical: str, lang: str) -> str:
    """Return the display string for *canonical* in the given language."""
    canonical = _color_canonical(canonical)
    if lang == "pt":
        return _COLOR_EN_TO_PT.get(canonical, canonical)
    return canonical


def _color_display_values(lang: str) -> List[str]:
    """Ordered list of color display names for *lang*."""
    if lang == "pt":
        return [_COLOR_EN_TO_PT[k] for k in _COLOR_EN_ORDER]
    return list(_COLOR_EN_ORDER)


def _color_to_english(color_str: str) -> str:
    """Convert any color name (PT or EN) to English for internal logic."""
    return _color_canonical(color_str)


