APP_TITLE = "SynROV Command Center - Ai Bot v1.0 - by Douglas Santana // @spidoug"


def synrov_identification_text() -> str:
    return APP_TITLE


def clamp(v: float, lo: float, hi: float) -> float:
    return max(lo, min(hi, float(v)))


def safe_float(v: Any, default: float = 0.0) -> float:
    try:
        if v is None:
            return default
        return float(v)
    except Exception:
        return default


def safe_int(v: Any, default: int = 0) -> int:
    try:
        if v is None:
            return default
        return int(float(v))
    except Exception:
        return default


def mean_abs(values: List[float]) -> float:
    if not values:
        return 0.0
    return sum(abs(safe_float(v)) for v in values) / max(len(values), 1)


def normalize_text(text: str) -> str:
    t = unicodedata.normalize("NFKD", str(text or ""))
    t = "".join(ch for ch in t if not unicodedata.combining(ch))
    t = t.lower()
    t = re.sub(r"[^a-z0-9\s]", " ", t)
    t = re.sub(r"\s+", " ", t).strip()
    return t


def has_any_token(text: str, tokens: List[str]) -> bool:
    toks = set(normalize_text(text).split())
    return any(normalize_text(tok) in toks for tok in tokens if tok)


def contains_any(text: str, phrases: List[str]) -> bool:
    t = normalize_text(text)
    return any(normalize_text(p) in t for p in phrases if p)


def wrap_signed(v: float) -> float:
    return clamp(v, -180.0, 180.0)


def wrap_abs(v: float) -> float:
    return clamp(abs(v), 0.0, 180.0)


def voice_vector(intent: str, confidence: float) -> List[float]:
    onehot = [0.0] * len(VOICE_INTENTS)
    idx = VOICE_INDEX.get(str(intent or "none"), 0)
    onehot[idx] = clamp(confidence, 0.0, 1.0)
    return onehot


def format_float(v: float, n: int = 2) -> str:
    try:
        return f"{float(v):.{n}f}"
    except Exception:
        return str(v)


def json_compatible(value: Any) -> Any:
    if np is not None:
        try:
            if isinstance(value, np.generic):
                return value.item()
            if isinstance(value, np.ndarray):
                return [json_compatible(v) for v in value.tolist()]
        except Exception:
            pass
    if isinstance(value, dict):
        return {str(k): json_compatible(v) for k, v in value.items()}
    if isinstance(value, (list, tuple)):
        return [json_compatible(v) for v in value]
    if isinstance(value, Path):
        return str(value)
    return value


def manipulator_rate_limits(rate_limits: Optional[Dict[str, float]] = None) -> List[float]:
    limits = rate_limits or MANIP_MODEL_RATE_LIMIT_DPS
    return [max(0.0, safe_float(limits.get(key, MANIP_MODEL_RATE_LIMIT_DPS[key]))) for key in MANIP_KEYS]


def clamp_manipulator_rate_vector(values: List[float], rate_limits: Optional[Dict[str, float]] = None) -> List[float]:
    raw = [safe_float(v) for v in list(values or [])]
    if len(raw) < len(MANIP_KEYS):
        raw.extend([0.0] * (len(MANIP_KEYS) - len(raw)))
    raw = raw[: len(MANIP_KEYS)]
    limits = manipulator_rate_limits(rate_limits)
    return [clamp(raw[i], -limits[i], limits[i]) for i in range(len(MANIP_KEYS))]


def manipulator_rate_from_delta_hint(delta_values: List[float]) -> List[float]:
    """Convert a desired displacement into a learnable smooth velocity target.

    Manual/UI/voice commands often store "how far the target pose is". Training
    the model directly on that absolute displacement teaches jumps. This converts
    the same intention into a proportional velocity, capped per joint, so repeated
    examples teach a ramp instead of a teleport.
    """
    raw = [safe_float(v) for v in list(delta_values or [])]
    if len(raw) < len(MANIP_KEYS):
        raw.extend([0.0] * (len(MANIP_KEYS) - len(raw)))
    out: List[float] = []
    limits = manipulator_rate_limits(MANIP_TRAINING_RATE_LIMIT_DPS)
    for i, value in enumerate(raw[: len(MANIP_KEYS)]):
        out.append(clamp(value * MANIP_HINT_PROPORTIONAL_GAIN, -limits[i], limits[i]))
    return out


def normalize_training_target(robot: str, target: List[float], source: str = "observe", from_hint: bool = False) -> List[float]:
    robot = normalize_robot_name(robot, robot)
    source_norm = normalize_text(str(source or "observe")) or "observe"
    if robot == "Manipulator":
        if from_hint and source_norm in {"manual", "voice"}:
            return manipulator_rate_from_delta_hint(target)
        return clamp_manipulator_rate_vector(target, MANIP_TRAINING_RATE_LIMIT_DPS)
    if robot == "Vehicle":
        raw = [safe_float(v) for v in list(target or [])]
        if len(raw) < 4:
            raw.extend([0.0] * (4 - len(raw)))
        return [clamp(raw[0], -1.0, 1.0), clamp(raw[1], -1.0, 1.0), clamp(raw[2], -1.0, 1.0), clamp(raw[3], -1.0, 1.0)]
    raw = [safe_float(v) for v in list(target or [])]
    if len(raw) < 6:
        raw.extend([0.0] * (6 - len(raw)))
    return [clamp(v, -1.0, 1.0) for v in raw[:6]]


def inference_dt_from_period_ms(period_ms: Any) -> float:
    return clamp(safe_float(period_ms, 260.0) / 1000.0, MANIP_MODEL_MIN_DT_S, MANIP_MODEL_MAX_DT_S)


def clamp_member_pose(pose: Dict[str, float]) -> Dict[str, float]:
    """Clamp manipulator UI/servo angles to the same limits used by SynROV."""
    normalized: Dict[str, float] = {}
    defaults = {
        "base": 180.0,
        "upper": 150.0,
        "fore": 70.0,
        "forearm_roll": 90.0,
        "wrist_pitch": 95.0,
        "wrist_rot": 130.0,
        "grip": 0.0,
    }
    source = dict(pose or {})
    for key in MANIP_KEYS:
        lo, hi = PROCESSING_MANIP_LIMITS.get(key, (0.0, 359.0))
        value = safe_float(source.get(key, defaults.get(key, (lo + hi) * 0.5)), defaults.get(key, (lo + hi) * 0.5))
        if key == "base":
            value = value % 360.0
        normalized[key] = clamp(value, lo, hi)
    return normalized


VALID_ROBOT_NAMES = ("Manipulator", "Vehicle", "Drone")


def normalize_robot_name(value: Any, default: str = "Manipulator") -> str:
    raw = str(value or "").strip()
    if not raw:
        return default
    lookup = {
        "manipulator": "Manipulator",
        "arm": "Manipulator",
        "manip": "Manipulator",
        "vehicle": "Vehicle",
        "rov": "Vehicle",
        "ugv": "Vehicle",
        "drone": "Drone",
        "uav": "Drone",
        "quadcopter": "Drone",
    }
    normalized = lookup.get(raw.lower())
    if normalized:
        return normalized
    for candidate in VALID_ROBOT_NAMES:
        if raw.lower() == candidate.lower():
            return candidate
    return default


def resolve_active_robot_name(state: Any, fallback: str = "Manipulator") -> str:
    preferred = normalize_robot_name(getattr(state, "mode", "") or "", "")
    if preferred:
        return preferred
    detected = normalize_robot_name(getattr(state, "robot", "") or "", "")
    if detected:
        return detected
    return normalize_robot_name(fallback, "Manipulator")


def runtime_mode_label(state: Any) -> str:
    sim = getattr(state, "simulation", None)
    if sim is True:
        return "simulation"
    if sim is False:
        return "runtime"
    return "pending"


