@dataclass
class SynROVState:
    connected: bool = False
    status: str = "disconnected"
    mode: str = "Manipulator"
    robot: str = "Manipulator"
    simulation: Optional[bool] = None
    connection_ts: float = 0.0
    telemetry_bootstrap: bool = False
    leap_enabled: bool = False
    leap_available: bool = False
    joystick_enabled: bool = False
    joystick_connected: bool = False
    control_owner: str = "none"
    telemetry_source: str = "local"
    communication_protocol: str = "ascii"
    sensors: Dict[str, Any] = field(default_factory=dict)
    gps: Dict[str, Any] = field(default_factory=dict)
    control: Dict[str, Any] = field(default_factory=dict)
    snapshot: Dict[str, Any] = field(default_factory=dict)
    servos: Dict[int, int] = field(default_factory=dict)
    last_frame_pil: Optional[Any] = None
    last_frame_ts: float = 0.0
    last_msg_ts: float = 0.0
    last_telemetry_ts: float = 0.0
    telemetry_alive: bool = False
    frame_counter: int = 0
    telemetry_counter: int = 0
    last_runtime: str = ""


def pose_from_state(state: SynROVState) -> Dict[str, float]:
    s = state.sensors
    servos = state.servos
    pose = {
        "base": safe_float(s.get("base_deg", servos.get(0, 180.0)), 180.0),
        "upper": safe_float(s.get("upper_deg", servos.get(1, 45.0)), 45.0),
        "fore": safe_float(s.get("fore_deg", servos.get(2, 180.0)), 180.0),
        "forearm_roll": safe_float(s.get("forearm_roll_deg", servos.get(3, 90.0)), 90.0),
        "wrist_pitch": safe_float(s.get("wrist_pitch_deg", servos.get(4, 90.0)), 90.0),
        "wrist_rot": safe_float(s.get("wrist_rot_deg", servos.get(5, 90.0)), 90.0),
        "grip": safe_float(s.get("grip_deg", servos.get(6, 50.0)), 50.0),
    }
    for i, k in enumerate(MANIP_KEYS):
        if i in servos:
            pose[k] = safe_float(servos.get(i), pose[k])
    return pose


def ui_pose_to_armj_values(pose: Dict[str, float]) -> List[int]:
    p = clamp_member_pose({k: safe_float(v) for k, v in dict(pose or {}).items()})
    base_member = int(round((safe_float(p.get("base", 180.0)) - 180.0) % 360.0))
    upper_member = int(round(clamp(safe_float(p.get("upper", 45.0)) - 45.0, -180.0, 180.0)))
    fore_member = int(round(clamp(safe_float(p.get("fore", 180.0)) - 180.0, -180.0, 180.0)))
    forearm_roll_member = int(round(clamp(safe_float(p.get("forearm_roll", 90.0)) - 90.0, -180.0, 180.0)))
    wrist_pitch_member = int(round(clamp(safe_float(p.get("wrist_pitch", 90.0)) - 90.0, -180.0, 180.0)))
    wrist_rot_member = int(round(clamp(safe_float(p.get("wrist_rot", 90.0)) - 90.0, -180.0, 180.0)))
    grip_member = int(round(clamp(safe_float(p.get("grip", 50.0)), 0.0, 100.0)))
    return [
        base_member,
        upper_member,
        fore_member,
        forearm_roll_member,
        wrist_pitch_member,
        wrist_rot_member,
        grip_member,
    ]


def _normalize_armj_pwm_values(pwm: Optional[List[int]] = None) -> List[int]:
    values = list(pwm or [])[:4]
    while len(values) < 4:
        values.append(0)
    return [int(clamp(safe_int(v), 0, 100)) for v in values[:4]]


def build_armj_command(pose: Dict[str, float], pwm: Optional[List[int]] = None, smooth_weights: Optional[List[float]] = None) -> str:
    vals = ui_pose_to_armj_values(pose)
    payload = list(vals) + _normalize_armj_pwm_values(pwm)
    return "ARMJ=" + ",".join(str(v) for v in payload)


def nudge_manipulator_pose(pose: Dict[str, float], intent: str, amount: float = 8.0) -> Dict[str, float]:
    p = dict(pose)
    if intent == "arm_up":
        # This arm firmware/rig is inverted on the vertical axis: moving up must increase upper.
        p["upper"] = clamp(p["upper"] + amount, 0, 180)
    elif intent == "arm_down":
        # Moving down must decrease upper to keep the physical command proper.
        p["upper"] = clamp(p["upper"] - amount, 0, 180)
    elif intent == "arm_left":
        # SynROV manipulator base is physically inverted: operator-left is positive from the 180° centre.
        p["base"] = clamp(p["base"] + amount, 0, 359)
    elif intent == "arm_right":
        # Operator-right is negative from the 180° centre.
        p["base"] = clamp(p["base"] - amount, 0, 359)
    elif intent == "grip_open":
        p["grip"] = clamp(p["grip"] + amount, 0, 100)
    elif intent == "grip_close":
        p["grip"] = clamp(p["grip"] - amount, 0, 100)
    elif intent == "wrist_up":
        # Physical SynROV wrist pitch is positive-up in the Processing bridge.
        p["wrist_pitch"] = clamp(p["wrist_pitch"] + amount, 0, 359)
    elif intent == "wrist_down":
        p["wrist_pitch"] = clamp(p["wrist_pitch"] - amount, 0, 359)
    elif intent == "wrist_left":
        # Physical SynROV wrist rotation is positive-left from the operator view.
        p["wrist_rot"] = clamp(p["wrist_rot"] + amount, 0, 359)
    elif intent == "wrist_right":
        p["wrist_rot"] = clamp(p["wrist_rot"] - amount, 0, 359)
    return p


# -----------------------------------------------------------------------------
# Voice parser
# -----------------------------------------------------------------------------
class RichVoiceParser:
    def parse(self, text: str, robot: str) -> Tuple[str, float]:
        t = normalize_text(text)
        if not t:
            return "none", 0.0

        if contains_any(t, ["seguir musica", "acompanhar musica", "dance with music", "music follow", "acompanhar som"]):
            return "music_follow", 0.95
        if contains_any(t, ["pegar objeto", "pega objeto", "grab object", "grasp object", "apanhar objeto"]):
            return "object_grasp", 0.95

        if robot == "Manipulator":
            if ((has_any_token(t, ["abrir", "abra", "open"]) and has_any_token(t, ["garra", "grip", "gripper"])) or
                contains_any(t, ["abrir garra", "abra a garra", "soltar objeto", "open gripper"])):
                return "grip_open", 1.0
            if ((has_any_token(t, ["fechar", "feche", "close"]) and has_any_token(t, ["garra", "grip", "gripper"])) or
                contains_any(t, ["fechar garra", "feche a garra", "pegar objeto", "close gripper"])):
                return "grip_close", 1.0
            if ((has_any_token(t, ["subir", "suba", "levantar", "levante", "erguer", "erga", "raise", "up"]) and has_any_token(t, ["braco", "arm"])) or
                contains_any(t, ["levantar o braco", "erguer o braco", "subir braco", "arm up", "raise arm"])):
                return "arm_up", 1.0
            if ((has_any_token(t, ["descer", "desca", "abaixar", "abaixe", "lower", "down"]) and has_any_token(t, ["braco", "arm"])) or
                contains_any(t, ["abaixar o braco", "descer braco", "lower arm", "arm down"])):
                return "arm_down", 1.0
            if ((has_any_token(t, ["esquerda", "left"]) and has_any_token(t, ["base", "braco", "arm", "girar", "rotate"])) or
                contains_any(t, ["girar base esquerda", "base esquerda", "left base"])):
                return "arm_left", 0.95
            if ((has_any_token(t, ["direita", "right"]) and has_any_token(t, ["base", "braco", "arm", "girar", "rotate"])) or
                contains_any(t, ["girar base direita", "base direita", "right base"])):
                return "arm_right", 0.95
            if ((has_any_token(t, ["punho", "wrist"]) and has_any_token(t, ["cima", "subir", "up"])) or contains_any(t, ["wrist up", "subir punho"])):
                return "wrist_up", 0.9
            if ((has_any_token(t, ["punho", "wrist"]) and has_any_token(t, ["baixo", "descer", "down"])) or contains_any(t, ["wrist down", "descer punho"])):
                return "wrist_down", 0.9
            if ((has_any_token(t, ["punho", "wrist"]) and has_any_token(t, ["esquerda", "left"])) or contains_any(t, ["wrist left", "punho esquerda"])):
                return "wrist_left", 0.9
            if ((has_any_token(t, ["punho", "wrist"]) and has_any_token(t, ["direita", "right"])) or contains_any(t, ["wrist right", "punho direita"])):
                return "wrist_right", 0.9
            if contains_any(t, ["posicao neutra", "voltar home", "voltar inicio", "home"]):
                return "home", 1.0
            return "none", 0.0

        if robot == "Vehicle":
            if contains_any(t, ["frente", "forward", "avancar", "andar frente"]):
                return "vehicle_forward", 1.0
            if contains_any(t, ["tras", "back", "re", "voltar"]):
                return "vehicle_back", 1.0
            if contains_any(t, ["esquerda", "left"]):
                return "vehicle_left", 1.0
            if contains_any(t, ["direita", "right"]):
                return "vehicle_right", 1.0
            if contains_any(t, ["parar", "stop"]):
                return "vehicle_stop", 1.0
            return "none", 0.0

        if contains_any(t, ["subir", "up"]):
            return "drone_up", 1.0
        if contains_any(t, ["descer", "down"]):
            return "drone_down", 1.0
        if contains_any(t, ["frente", "forward"]):
            return "drone_forward", 1.0
        if contains_any(t, ["tras", "back"]):
            return "drone_back", 1.0
        if contains_any(t, ["esquerda", "left"]):
            return "drone_left", 1.0
        if contains_any(t, ["direita", "right"]):
            return "drone_right", 1.0
        if contains_any(t, ["takeoff", "take off", "decolar", "decolagem"]):
            return "drone_takeoff", 1.0
        if contains_any(t, ["land", "pousar"]):
            return "drone_land", 1.0
        return "none", 0.0


# -----------------------------------------------------------------------------
# Audio and vision features
# -----------------------------------------------------------------------------
def extract_audio_features(samples: Optional[Any], sample_rate: int = 16000, prev_rms: float = 0.0) -> List[float]:
    if np is None or samples is None:
        return [0.0] * len(AUDIO_KEYS)
    try:
        x = np.asarray(samples, dtype=np.float32).reshape(-1)
    except Exception:
        return [0.0] * len(AUDIO_KEYS)
    if x.size == 0:
        return [0.0] * len(AUDIO_KEYS)
    x = x - float(np.mean(x))
    peak = float(np.max(np.abs(x)) + 1e-9)
    rms = float(np.sqrt(np.mean(np.square(x))) + 1e-9)
    zcr = float(np.mean(np.abs(np.diff(np.signbit(x).astype(np.float32))))) if x.size > 2 else 0.0
    spec = np.abs(np.fft.rfft(x))
    freqs = np.fft.rfftfreq(x.size, d=1.0 / max(sample_rate, 1))
    power = float(np.sum(spec) + 1e-9)
    centroid = float(np.sum(freqs * spec) / power / (sample_rate / 2.0 + 1e-9))
    low = float(np.sum(spec[(freqs >= 20) & (freqs < 250)]) / power)
    mid = float(np.sum(spec[(freqs >= 250) & (freqs < 2000)]) / power)
    high = float(np.sum(spec[freqs >= 2000]) / power)
    pulse = clamp((rms - prev_rms) * 12.0, -1.0, 1.0)
    return [rms, peak, zcr, centroid, low, mid, high, pulse]


def pil_to_feature_vector(image: Any, size: Tuple[int, int] = (20, 12), hist_bins: int = 12) -> List[float]:
    if Image is None or np is None or image is None:
        return [0.0] * (hist_bins + 8)
    try:
        img = image.convert("L").resize(size)
        arr = np.asarray(img, dtype=np.float32) / 255.0
        hist, _ = np.histogram(arr, bins=hist_bins, range=(0.0, 1.0), density=True)
        mean = float(arr.mean())
        std = float(arr.std())
        center = float(arr[arr.shape[0] // 4: 3 * arr.shape[0] // 4, arr.shape[1] // 4: 3 * arr.shape[1] // 4].mean())
        gradx = np.abs(np.diff(arr, axis=1)).mean() if arr.shape[1] > 1 else 0.0
        grady = np.abs(np.diff(arr, axis=0)).mean() if arr.shape[0] > 1 else 0.0
        bright_top = float(arr[: max(1, arr.shape[0] // 3), :].mean())
        bright_bottom = float(arr[-max(1, arr.shape[0] // 3):, :].mean())
        bright_left = float(arr[:, : max(1, arr.shape[1] // 3)].mean())
        bright_right = float(arr[:, -max(1, arr.shape[1] // 3):].mean())
        return [float(v) for v in hist.tolist()] + [mean, std, center, gradx, grady, bright_top - bright_bottom, bright_left - bright_right, arr.max()]
    except Exception:
        return [0.0] * (hist_bins + 8)


@dataclass
class VisionInfo:
    confidence: float = 0.0
    dx: float = 0.0
    dy: float = 0.0
    area: float = 0.0
    width: float = 0.0
    height: float = 0.0
    centered: float = 0.0
    close: float = 0.0
    source: str = "none"
    label: str = "none"

    def as_vector(self) -> List[float]:
        return [self.confidence, self.dx, self.dy, self.area, self.width, self.height, self.centered, self.close]


def detect_object_from_pil(image: Any, color_name: str = "green") -> VisionInfo:
    if Image is None or np is None or image is None:
        return VisionInfo()
    if cv2 is None:
        return VisionInfo(source="frame", label="cv2_missing")
    try:
        arr = np.array(image.convert("RGB"))
        bgr = cv2.cvtColor(arr, cv2.COLOR_RGB2BGR)
        hsv = cv2.cvtColor(bgr, cv2.COLOR_BGR2HSV)

        presets = {
            "green": [((35, 40, 40), (90, 255, 255))],
            "red": [((0, 70, 50), (10, 255, 255)), ((170, 70, 50), (180, 255, 255))],
            "blue": [((90, 50, 40), (135, 255, 255))],
            "yellow": [((18, 70, 70), (38, 255, 255))],
            "generic": [((0, 0, 40), (180, 80, 255))],
        }
        ranges = presets.get(color_name, presets["green"])
        mask = None
        for lo, hi in ranges:
            part = cv2.inRange(hsv, np.array(lo, dtype=np.uint8), np.array(hi, dtype=np.uint8))
            mask = part if mask is None else cv2.bitwise_or(mask, part)
        mask = cv2.medianBlur(mask, 5)
        contours, _ = cv2.findContours(mask, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)
        if not contours:
            return VisionInfo(source="frame", label="no_object")
        cnt = max(contours, key=cv2.contourArea)
        area_px = float(cv2.contourArea(cnt))
        h, w = mask.shape[:2]
        if area_px < max(30.0, w * h * 0.0004):
            return VisionInfo(source="frame", label="tiny")
        x, y, bw, bh = cv2.boundingRect(cnt)
        cx = x + bw / 2.0
        cy = y + bh / 2.0
        dx = ((cx / max(w, 1)) - 0.5) * 2.0
        dy = ((cy / max(h, 1)) - 0.5) * 2.0
        area = area_px / max(w * h, 1)
        centered = 1.0 if abs(dx) < 0.12 and abs(dy) < 0.12 else 0.0
        close = 1.0 if area > 0.08 else 0.0
        conf = clamp(area * 6.0 + centered * 0.25, 0.0, 1.0)
        return VisionInfo(confidence=conf, dx=dx, dy=dy, area=area, width=bw / max(w, 1), height=bh / max(h, 1), centered=centered, close=close, source="frame", label=color_name)
    except Exception:
        return VisionInfo(source="frame", label="vision_error")


# -----------------------------------------------------------------------------
# SynROV bridge
# -----------------------------------------------------------------------------
class SynROVBridge:
    def __init__(self, event_queue: "queue.Queue[Tuple[str, Any]]") -> None:
        self.event_queue = event_queue
        self.state = SynROVState()
        self.uri = DEFAULT_URI
        self._lock = threading.Lock()
        self._control_lock = threading.Lock()
        self._ws_app = None
        self._ws_thread: Optional[threading.Thread] = None
        self._hb_thread: Optional[threading.Thread] = None
        self._stop = threading.Event()
        self._last_sync_request = 0.0
        self._last_control_send_ts = 0.0
        self._control_send_interval_s = 0.08
        self._send_seq = 0

    def _bootstrap_online_telemetry(self) -> None:
        now = time.time()
        self.state.connected = True
        self.state.connection_ts = now
        self.state.last_msg_ts = now
        if str(self.state.status or "").strip().lower() in {"", "disconnected", "offline"}:
            self.state.status = "connected"
        if str(self.state.telemetry_source or "").strip().lower() in {"", "local"}:
            self.state.telemetry_source = "bootstrap"

        if not self.state.sensors:
            pose = pose_from_state(self.state)
            bootstrap = {
                "base_deg": safe_float(pose.get("base", 180.0), 180.0),
                "upper_deg": safe_float(pose.get("upper", 45.0), 45.0),
                "fore_deg": safe_float(pose.get("fore", 180.0), 180.0),
                "forearm_roll_deg": safe_float(pose.get("forearm_roll", 90.0), 90.0),
                "wrist_pitch_deg": safe_float(pose.get("wrist_pitch", 90.0), 90.0),
                "wrist_rot_deg": safe_float(pose.get("wrist_rot", 90.0), 90.0),
                "grip_deg": safe_float(pose.get("grip", 90.0), 90.0),
            }
            self.state.sensors.update(bootstrap)
            self.state.telemetry_counter += 1
            self.state.telemetry_bootstrap = True
        else:
            self.state.telemetry_bootstrap = False
        self.state.last_telemetry_ts = now
        self.state.telemetry_alive = True

    def _mark_telemetry_alive(self) -> None:
        now = time.time()
        self.state.connected = True
        self.state.last_msg_ts = now
        self.state.last_telemetry_ts = now
        self.state.telemetry_alive = True
        if str(self.state.status or "").strip().lower() in {"", "disconnected", "offline"}:
            self.state.status = "connected"
        if str(self.state.telemetry_source or "").strip().lower() in {"", "local"}:
            self.state.telemetry_source = "stream"

    def _request_sync(self, force: bool = False) -> None:
        now = time.time()
        interval = 0.75 if force else 2.5
        if (now - self._last_sync_request) < interval:
            return
        self.send_json({"sync": True})
        self._last_sync_request = now

    def _uri_candidates(self, uri: str) -> List[str]:
        raw = str(uri or "").strip() or DEFAULT_URI
        candidates: List[str] = []

        def add(value: str) -> None:
            value = str(value or "").strip()
            if value and value not in candidates:
                candidates.append(value)

        add(raw)
        if not re.match(r"^wss?://", raw, flags=re.IGNORECASE):
            add("ws://" + raw)
        cleaned = raw.rstrip("/")
        if cleaned:
            add(cleaned)
            add(cleaned + "/")
        for current in list(candidates):
            if "127.0.0.1" in current:
                add(current.replace("127.0.0.1", "localhost"))
            if "localhost" in current:
                add(current.replace("localhost", "127.0.0.1"))
        return candidates or [DEFAULT_URI]

    def connect(self, uri: str) -> None:
        if websocket is None:
            raise RuntimeError("websocket-client não instalado")
        self.disconnect()
        self._stop.clear()
        self.state.status = "connecting"
        self.state.connected = False
        self.state.telemetry_alive = False
        self.event_queue.put(("state", None))
        candidates = self._uri_candidates(uri)
        current_uri = {"value": candidates[0]}

        def on_open(ws):
            self._bootstrap_online_telemetry()
            self.send_json({"client": "connect"})
            self._request_sync(force=True)
            self.event_queue.put(("log", f"[ws] conectado em {current_uri['value']} | telemetria inicial bootstrap ativada"))
            self.event_queue.put(("state", None))

        def on_message(ws, message: str):
            self.state.last_msg_ts = time.time()
            self._handle_message(message)

        def on_error(ws, error):
            self.state.connected = False
            self.state.telemetry_alive = False
            self.state.status = "error"
            self.event_queue.put(("log", f"[ws] erro em {current_uri['value']}: {error}"))
            self.event_queue.put(("state", None))

        def on_close(ws, code, msg):
            self.state.connected = False
            self.state.telemetry_alive = False
            self.state.status = "disconnected"
            self.event_queue.put(("log", f"[ws] desconectado de {current_uri['value']} ({code}, {msg})"))
            self.event_queue.put(("state", None))

        def runner():
            for candidate in candidates:
                if self._stop.is_set() or self.state.connected:
                    return
                current_uri["value"] = candidate
                self.uri = candidate
                self.event_queue.put(("log", f"[ws] tentando conectar em {candidate}"))
                try:
                    self._ws_app = websocket.WebSocketApp(candidate, on_open=on_open, on_message=on_message, on_error=on_error, on_close=on_close)
                    self._ws_app.run_forever(http_proxy_host=None, http_proxy_port=None)
                except Exception as exc:
                    self.event_queue.put(("log", f"[ws] falha ao iniciar socket em {candidate}: {exc}"))
                if self.state.connected or self._stop.is_set():
                    return
                time.sleep(0.25)
            if not self.state.connected and not self._stop.is_set():
                self.state.status = "disconnected"
                self.event_queue.put(("log", "[ws] não foi possível conectar ao SynROV. Verifique se o servidor WebSocket do SynROV está ativo e se a URI/porta estão corretas."))
                self.event_queue.put(("state", None))

        self._ws_thread = threading.Thread(target=runner, daemon=True)
        self._ws_thread.start()
        self._hb_thread = threading.Thread(target=self._heartbeat_loop, daemon=True)
        self._hb_thread.start()

    def disconnect(self) -> None:
        self._stop.set()
        try:
            self.send_json({"client": "disconnect"})
        except Exception:
            pass
        if self._ws_app is not None:
            try:
                self._ws_app.close()
            except Exception:
                pass
        self.state.connected = False
        self.state.simulation = None
        self.state.telemetry_bootstrap = False
        self.state.telemetry_alive = False
        self.state.status = "disconnected"
        self.state.telemetry_source = "local"
        self.state.gps.clear()
        self.state.control.clear()
        self.state.snapshot.clear()
        self._last_sync_request = 0.0

    def _heartbeat_loop(self) -> None:
        while not self._stop.is_set():
            time.sleep(0.6)
            if not self.state.connected:
                continue
            try:
                self.send_json({"client": "ping"})
            except Exception:
                pass
            telem_age = (time.time() - self.state.last_telemetry_ts) if self.state.last_telemetry_ts else 999.0
            try:
                if telem_age > 1.25:
                    self._request_sync(force=True)
                elif telem_age > 6.0:
                    self._request_sync()
            except Exception:
                pass

    def _handle_message(self, message: str) -> None:
        try:
            payload = json.loads(message)
        except Exception:
            self.event_queue.put(("log", f"[ws/raw] {message[:200]}"))
            return
        if not isinstance(payload, dict):
            return

        changed = False
        frame_payload = payload.get("frame") or payload.get("dataUrl") or payload.get("image")
        if frame_payload and (payload.get("type") in {None, "", "frame", "image"} or "frame" in payload or "dataUrl" in payload):
            self._mark_telemetry_alive()
            self._handle_frame(frame_payload)
            changed = True

        snapshot = payload.get("snapshot")
        if isinstance(snapshot, dict):
            self.state.snapshot = dict(snapshot)
            snapshot_robot = snapshot.get("robot") or snapshot.get("detectedRobot")
            if snapshot_robot:
                resolved_robot = normalize_robot_name(snapshot_robot, self.state.robot or "Manipulator")
                self.state.robot = resolved_robot
                self.state.mode = resolved_robot
                changed = True
            system_block = snapshot.get("system")
            sensor_block = snapshot.get("sensors")
            gps_block = snapshot.get("gps")
            control_block = snapshot.get("control")
            if isinstance(sensor_block, dict):
                self.state.sensors.update(sensor_block)
                self.state.telemetry_bootstrap = False
                self._mark_telemetry_alive()
                changed = True
            if isinstance(gps_block, dict):
                self.state.gps.update(gps_block)
                changed = True
            if isinstance(control_block, dict):
                self.state.control.update(control_block)
                changed = True
            if isinstance(system_block, dict):
                for src_key, dst_attr in [
                    ("status", "status"), ("mode", "mode"), ("robot", "robot"), ("detectedRobot", "robot"), ("controlOwner", "control_owner"),
                    ("telemetrySource", "telemetry_source"), ("communicationProtocol", "communication_protocol"), ("simulation", "simulation"),
                    ("leapEnabled", "leap_enabled"), ("leapAvailable", "leap_available"),
                    ("joystickEnabled", "joystick_enabled"), ("joystickConnected", "joystick_connected"),
                ]:
                    if src_key in system_block:
                        value = system_block.get(src_key)
                        if dst_attr in {"leap_enabled", "leap_available", "joystick_enabled", "joystick_connected"}:
                            value = bool(value)
                        if dst_attr in {"robot", "mode"}:
                            value = normalize_robot_name(value, self.state.robot or "Manipulator")
                        setattr(self.state, dst_attr, value)
                        self._mark_telemetry_alive()
                        changed = True

        if isinstance(payload.get("sensors"), dict):
            self.state.sensors.update(payload["sensors"])
            self.state.telemetry_bootstrap = False
            self._mark_telemetry_alive()
            changed = True
        if isinstance(payload.get("gps"), dict):
            self.state.gps.update(payload["gps"])
            changed = True
        if isinstance(payload.get("control"), dict):
            self.state.control.update(payload["control"])
            changed = True
        if "servo" in payload and "angle" in payload:
            self.state.servos[safe_int(payload.get("servo"))] = safe_int(payload.get("angle"))
            self._mark_telemetry_alive()
            changed = True
        for src_key, dst_attr in [
            ("status", "status"), ("mode", "mode"), ("robot", "robot"), ("detectedRobot", "robot"), ("controlOwner", "control_owner"),
            ("telemetrySource", "telemetry_source"), ("communicationProtocol", "communication_protocol"), ("simulation", "simulation"),
        ]:
            if src_key in payload:
                value = payload.get(src_key)
                if dst_attr in {"robot", "mode"}:
                    value = normalize_robot_name(value, self.state.robot or "Manipulator")
                setattr(self.state, dst_attr, value)
                self._mark_telemetry_alive()
                changed = True
        for src_key, dst_attr in [
            ("leapEnabled", "leap_enabled"), ("leapAvailable", "leap_available"),
            ("joystickEnabled", "joystick_enabled"), ("joystickConnected", "joystick_connected"),
        ]:
            if src_key in payload:
                setattr(self.state, dst_attr, bool(payload.get(src_key)))
                self._mark_telemetry_alive()
                changed = True
        if changed:
            # One increment per inbound message that caused any state change
            # (sensor, servo, frame header, status).  Previously servo and
            # status-only messages bypassed the counter and kept the bar at 0.
            self.state.telemetry_counter += 1
            self.event_queue.put(("state", None))

    def _handle_frame(self, image_payload: Optional[str]) -> None:
        if not image_payload or Image is None:
            return
        try:
            text = str(image_payload).strip()
            if text.startswith("data:image/") and "," in text:
                text = text.split(",", 1)[1]
            text = re.sub(r"\s+", "", text)
            raw = base64.b64decode(text, validate=False)
            img = Image.open(io.BytesIO(raw)).convert("RGB")
            self.state.last_frame_pil = img
            self.state.last_frame_ts = time.time()
            self.state.frame_counter += 1
            self.event_queue.put(("frame", None))
        except Exception as exc:
            self.event_queue.put(("log", f"[frame] decode error: {exc}"))

    def _with_transport_metadata(self, payload: Dict[str, Any]) -> Dict[str, Any]:
        outbound = dict(payload or {})
        outbound.setdefault("source", "synrov_aibot")
        outbound.setdefault("sentAt", time.time())
        self._send_seq += 1
        outbound.setdefault("seq", self._send_seq)
        return outbound

    def send_json(self, payload: Dict[str, Any]) -> None:
        if self._ws_app is None:
            return
        with self._lock:
            outbound = self._with_transport_metadata(payload)
            data = json.dumps(outbound, ensure_ascii=False)
            self._ws_app.send(data)

    def send_control(self, payload: Dict[str, Any]) -> None:
        self.state.last_runtime = json.dumps(payload, ensure_ascii=False)
        with self._control_lock:
            now = time.time()
            wait_s = self._control_send_interval_s - (now - self._last_control_send_ts)
            if wait_s > 0:
                time.sleep(min(wait_s, self._control_send_interval_s))
            self._last_control_send_ts = time.time()
            outbound = dict(payload or {})
            outbound.setdefault("type", "control_intent")
            outbound.setdefault("controlSource", "synrov_aibot")
            outbound.setdefault("origin", "synrov_aibot")
            self.send_json(outbound)

    def send_runtime(self, command: str) -> None:
        raise RuntimeError("Raw runtime commands are disabled. Use current-schema control/action blocks.")

    def command_manipulator_pose(self, pose: Dict[str, float]) -> str:
        p = clamp_member_pose(pose)
        angles = [int(round(clamp(p.get(key, 0.0), PROCESSING_MANIP_LIMITS[key][0], PROCESSING_MANIP_LIMITS[key][1]))) for key in MANIP_KEYS]
        payload = {"type": "control_intent", "control": {"robot": "Manipulator", "manipulator": {"angles": angles}}}
        self.send_control(payload)
        return "CONTROL:Manipulator"

    def manip_home(self) -> None:
        self.send_control({"action": "home"})

    def send_vehicle(self, throttle: float, steer: float, cam_pan: float = 0.0, cam_tilt: float = 0.0) -> str:
        payload = {
            "type": "control_intent",
            "control": {
                "robot": "Vehicle",
                "drive": {
                    "mode": "arc",
                    "throttle": clamp(throttle, -1.0, 1.0),
                    "steer": clamp(steer, -1.0, 1.0),
                    "camPan": clamp(cam_pan, -90.0, 90.0),
                    "camTilt": clamp(cam_tilt, -45.0, 45.0),
                },
            }
        }
        self.send_control(payload)
        return "CONTROL:Vehicle"

    def send_drone(self, throttle: float, yaw: float, pitch: float, roll: float, strafe: float, forward: float) -> str:
        payload = {
            "type": "control_intent",
            "control": {
                "robot": "Drone",
                "flight": {
                    "throttle": clamp(throttle, -1.0, 1.0),
                    "yaw": clamp(yaw, -1.0, 1.0),
                    "pitch": clamp(pitch, -1.0, 1.0),
                    "roll": clamp(roll, -1.0, 1.0),
                    "strafe": clamp(strafe, -1.0, 1.0),
                    "forward": clamp(forward, -1.0, 1.0),
                },
            }
        }
        self.send_control(payload)
        return "CONTROL:Drone"

    def drone_takeoff(self) -> None:
        self.send_control({"action": "takeoff"})

    def drone_land(self) -> None:
        self.send_control({"action": "land"})


# -----------------------------------------------------------------------------
# Voice + audio engine
# -----------------------------------------------------------------------------
class VoiceAudioEngine:
    def __init__(self, parser: RichVoiceParser, robot_getter, language_getter=None) -> None:
        self.parser = parser
        self.robot_getter = robot_getter
        self.language_getter = language_getter or (lambda: "pt")
        self.running = False
        self.last_text = ""
        self.last_norm = ""
        self.last_intent = "none"
        self.last_conf = 0.0
        self.last_text_ts = 0.0
        self.audio_level = 0.0
        self.audio_features = [0.0] * len(AUDIO_KEYS)
        self.audio_ts = 0.0
        self.last_sr_error = ""
        self._stream = None
        self._audio_lock = threading.Lock()
        self._speech_thread: Optional[threading.Thread] = None
        self._prev_rms = 0.0

    def start(self) -> None:
        if self.running:
            return
        self.running = True
        if sr is not None:
            self._speech_thread = threading.Thread(target=self._speech_loop, daemon=True)
            self._speech_thread.start()

    def stop(self) -> None:
        self.running = False
        try:
            if self._stream is not None:
                self._stream.stop()
                self._stream.close()
        except Exception:
            pass
        self._stream = None

    def inject_text(self, text: str) -> None:
        robot = self.robot_getter()
        intent, conf = self.parser.parse(text, robot)
        self.last_text = text.strip()
        self.last_norm = normalize_text(text)
        self.last_intent = intent
        self.last_conf = conf
        self.last_text_ts = time.time()

    def _audio_loop(self) -> None:
        """Stub — áudio capturado pelo PyAudio no GoogleVoiceAudioEngine."""
        pass

    def _recognition_languages(self) -> List[str]:
        try:
            lang = str(self.language_getter() or "").strip().lower()
        except Exception:
            lang = "pt"
        primary = "pt-BR" if lang.startswith("pt") else "en-US"
        fallback = "en-US" if primary == "pt-BR" else "pt-BR"
        return [primary, fallback]

    def _speech_loop(self) -> None:
        if sr is None:
            return
        recognizer = sr.Recognizer()
        try:
            recognizer.operation_timeout = 5.0
        except Exception:
            pass
        try:
            with sr.Microphone() as source:
                recognizer.adjust_for_ambient_noise(source, duration=0.10)
                while self.running:
                    try:
                        audio = recognizer.listen(source, timeout=1.0, phrase_time_limit=3.0)
                    except Exception:
                        continue
                    
                    _audio_snap = audio
                    def _recognize_snap(_aud=_audio_snap):
                        _text = ""
                        _err = ""
                        for _lang in self._recognition_languages():
                            try:
                                _text = recognizer.recognize_google(_aud, language=_lang)
                                if _text: break
                            except Exception as _exc:
                                _err = str(_exc)
                                _text = ""
                        if _text: self.inject_text(_text)
                        elif _err: self.last_sr_error = f"speech recognition: {_err}"
                    threading.Thread(target=_recognize_snap, daemon=True).start()
        except Exception as exc:
            self.last_sr_error = f"speech loop: {exc}"

    def context(self) -> Dict[str, Any]:
        with self._audio_lock:
            feats = list(self.audio_features)
            lvl = self.audio_level
            ats = self.audio_ts
        return {
            "raw": self.last_text,
            "text": self.last_text,
            "norm": self.last_norm,
            "intent": self.last_intent,
            "conf": self.last_conf,
            "text_age": time.time() - self.last_text_ts if self.last_text_ts else 999.0,
            "audio_features": feats,
            "audio_level": lvl,
            "audio_age": time.time() - ats if ats else 999.0,
            "error": self.last_sr_error,
        }


# -----------------------------------------------------------------------------
# Webcam helper
# -----------------------------------------------------------------------------
class WebcamSource:
    def __init__(self) -> None:
        self.cap = None
        self.enabled = False
        self.index = 0
        self.last_frame_pil = None

    def start(self, index: int = 0) -> None:
        if cv2 is None or Image is None:
            raise RuntimeError("opencv-python e pillow são necessários para webcam")
        self.stop()
        self.cap = cv2.VideoCapture(index)
        if self.cap is None or not self.cap.isOpened():
            try:
                if self.cap is not None:
                    self.cap.release()
            except Exception:
                pass
            self.cap = None
            self.enabled = False
            raise RuntimeError(f"não foi possível abrir a webcam no índice {index}")
        self.enabled = True
        self.index = index

    def stop(self) -> None:
        self.enabled = False
        if self.cap is not None:
            try:
                self.cap.release()
            except Exception:
                pass
        self.cap = None
        self.last_frame_pil = None

    def update(self) -> Optional[Any]:
        if not self.enabled or self.cap is None or cv2 is None or Image is None:
            return self.last_frame_pil
        ok, frame = self.cap.read()
        if not ok:
            return self.last_frame_pil
        rgb = cv2.cvtColor(frame, cv2.COLOR_BGR2RGB)
        self.last_frame_pil = Image.fromarray(rgb)
        return self.last_frame_pil


