@dataclass
class SampleRecord:
    timestamp: float
    robot: str
    source: str
    simulation: Optional[bool]
    leap_enabled: bool
    voice_text: str
    voice_norm: str
    voice_intent: str
    voice_confidence: float
    telemetry_feat: List[float]
    synrov_feat: List[float]
    webcam_feat: List[float]
    audio_feat: List[float]
    vision_feat: List[float]
    target: List[float]
    frame_path: str = ""

    def to_dict(self) -> Dict[str, Any]:
        return json_compatible({
            "timestamp": self.timestamp,
            "robot": self.robot,
            "source": self.source,
            "simulation": self.simulation,
            "leap_enabled": self.leap_enabled,
            "voice_text": self.voice_text,
            "voice_norm": self.voice_norm,
            "voice_intent": self.voice_intent,
            "voice_confidence": self.voice_confidence,
            "telemetry_feat": self.telemetry_feat,
            "synrov_feat": self.synrov_feat,
            "webcam_feat": self.webcam_feat,
            "audio_feat": self.audio_feat,
            "vision_feat": self.vision_feat,
            "target": self.target,
            "frame_path": self.frame_path,
        })


def _synrov_frame_file_candidates(frame_dir: Path = FRAME_DIR) -> List[Path]:
    """Return SynROV frame files ordered from oldest to newest."""
    try:
        folder = Path(frame_dir)
        if not folder.exists():
            return []
        files = [
            item for item in folder.iterdir()
            if item.is_file()
            and item.name.startswith("synrov_")
            and item.suffix.lower() in FRAME_FILE_EXTENSIONS
        ]
        files.sort(key=lambda path: (path.stat().st_mtime if path.exists() else 0.0, path.name))
        return files
    except Exception:
        return []


def _is_safe_synrov_frame_path(path_value: Any, frame_dir: Path = FRAME_DIR) -> Optional[Path]:
    """Return a deletable SynROV frame path inside the managed frame folder."""
    try:
        path_text = str(path_value or "").strip()
        if not path_text:
            return None
        path = Path(path_text).expanduser()
        if not path.is_absolute():
            path = Path(frame_dir) / path.name
        path = path.resolve()
        root = Path(frame_dir).resolve()
        if root not in path.parents and path != root:
            return None
        if not path.name.startswith("synrov_"):
            return None
        if path.suffix.lower() not in FRAME_FILE_EXTENSIONS:
            return None
        return path
    except Exception:
        return None


def frame_paths_from_rows(rows: List[Dict[str, Any]], frame_dir: Path = FRAME_DIR) -> List[Path]:
    """Collect managed frame files referenced by dataset rows."""
    out: List[Path] = []
    seen = set()
    for row in rows or []:
        if not isinstance(row, dict):
            continue
        path = _is_safe_synrov_frame_path(row.get("frame_path"), frame_dir)
        if path is None:
            continue
        key = str(path)
        if key not in seen:
            out.append(path)
            seen.add(key)
    return out


def training_frame_cleanup_snapshot(rows: List[Dict[str, Any]], frame_dir: Path = FRAME_DIR) -> List[Path]:
    """Build the frame snapshot that belongs to the current training window."""
    candidates: List[Path] = []
    candidates.extend(frame_paths_from_rows(rows, frame_dir))
    candidates.extend(_synrov_frame_file_candidates(frame_dir))
    out: List[Path] = []
    seen = set()
    for path in candidates:
        safe = _is_safe_synrov_frame_path(str(path), frame_dir)
        if safe is None:
            continue
        key = str(safe)
        if key in seen:
            continue
        seen.add(key)
        out.append(safe)
    return out


def delete_training_frame_files(paths: List[Path]) -> int:
    """Delete frame files from a completed training window."""
    deleted = 0
    for path in list(paths or []):
        safe = _is_safe_synrov_frame_path(str(path))
        if safe is None:
            continue
        try:
            if safe.exists() and safe.is_file():
                safe.unlink()
                deleted += 1
        except Exception:
            pass
    return deleted


def synrov_saved_frame_count(frame_dir: Path = FRAME_DIR) -> int:
    """Count managed frame files currently stored on disk."""
    return len(_synrov_frame_file_candidates(frame_dir))


class DatasetCollector:
    def __init__(self, dataset_path: Path) -> None:
        self.dataset_path = Path(dataset_path)
        self.collecting = False
        self.records_written = 0
        self.last_pose: Optional[Dict[str, float]] = None
        self.last_state_vector: Optional[List[float]] = None
        self.last_ts: float = 0.0

    def start(self) -> None:
        self.collecting = True
        self.last_pose = None
        self.last_state_vector = None
        self.last_ts = 0.0

    def stop(self) -> None:
        self.collecting = False

    def _telemetry_vector(self, state: SynROVState) -> List[float]:
        s = dict(state.sensors)
        pose = pose_from_state(state)
        s.setdefault("base_deg", pose["base"])
        s.setdefault("upper_deg", pose["upper"])
        s.setdefault("fore_deg", pose["fore"])
        s.setdefault("forearm_roll_deg", pose["forearm_roll"])
        s.setdefault("wrist_pitch_deg", pose["wrist_pitch"])
        s.setdefault("wrist_rot_deg", pose["wrist_rot"])
        s.setdefault("grip_deg", pose["grip"])
        return [safe_float(s.get(k, 0.0)) for k in TELEMETRY_KEYS]

    def _telemetry_vector_for_robot(self, state: SynROVState, robot: str) -> List[float]:
        """Alias for subclass compatibility. Subclasses may override for per-robot filtering."""
        return self._telemetry_vector(state)

    def _estimate_target(self, robot: str, state: SynROVState, dt: float) -> List[float]:
        pose = pose_from_state(state)
        if robot == "Manipulator":
            if self.last_pose is None:
                return [0.0] * len(MANIP_KEYS)
            delta: List[float] = []
            for key in MANIP_KEYS:
                if key == "base":
                    delta.append(shortest_base_delta_deg(safe_float(self.last_pose.get(key, pose.get(key, 0.0))), safe_float(pose.get(key, 0.0))))
                else:
                    delta.append(safe_float(pose.get(key, 0.0)) - safe_float(self.last_pose.get(key, 0.0)))
            rate = [v / max(dt, MANIP_MODEL_MIN_DT_S) for v in delta]
            return normalize_training_target("Manipulator", rate, source="observe", from_hint=False)
        # Vehicle and Drone: the training target should reflect the *commanded* action,
        # not a derivative of Manipulator-centric telemetry indices that don't exist for
        # these robots.  state.control is updated by send_vehicle/send_drone immediately
        # after each command, making it the ground truth for what the robot was told to do.
        if robot == "Vehicle":
            control = getattr(state, "control", {}) or {}
            drive = control.get("drive") if isinstance(control.get("drive"), dict) else {}
            throttle = clamp(safe_float(drive.get("throttle", 0.0)), -1.0, 1.0)
            steer = clamp(safe_float(drive.get("steer", 0.0)), -1.0, 1.0)
            cam_pan = clamp(safe_float(drive.get("camPan", state.sensors.get("vehicle_cam_pan_deg", 0.0))), -90.0, 90.0) / 90.0
            cam_tilt = clamp(safe_float(drive.get("camTilt", state.sensors.get("vehicle_cam_tilt_deg", 0.0))), -45.0, 45.0) / 45.0
            return [throttle, steer, cam_pan, cam_tilt]
        # Drone (6 DOF)
        control = getattr(state, "control", {}) or {}
        flight = control.get("flight") if isinstance(control.get("flight"), dict) else {}
        return [
            clamp(safe_float(flight.get("throttle", 0.0)), -1.0, 1.0),
            clamp(safe_float(flight.get("yaw", 0.0)), -1.0, 1.0),
            clamp(safe_float(flight.get("pitch", 0.0)), -1.0, 1.0),
            clamp(safe_float(flight.get("roll", 0.0)), -1.0, 1.0),
            clamp(safe_float(flight.get("strafe", 0.0)), -1.0, 1.0),
            clamp(safe_float(flight.get("forward", 0.0)), -1.0, 1.0),
        ]

    def maybe_append(
        self,
        state: SynROVState,
        robot: str,
        voice_ctx: Dict[str, Any],
        audio_feat: List[float],
        vision_info: VisionInfo,
        synrov_feat: List[float],
        webcam_feat: List[float],
        target_hint: Optional[List[float]] = None,
        source: str = "observe",
        save_frame_every: int = 10,
    ) -> Tuple[bool, Optional[SampleRecord]]:
        if not self.collecting:
            return False, None
        now = time.time()
        dt = now - self.last_ts if self.last_ts else 0.0
        telemetry_feat = self._telemetry_vector_for_robot(state, robot)
        estimated_target = self._estimate_target(robot, state, dt if dt > 0 else 0.1)
        use_hint = target_hint is not None
        # For the manipulator, only commands that truly represent joint displacement
        # are accepted as hints. Vision/music use observed telemetry because
        # those module vectors are semantic values, not joint angles.
        if robot == "Manipulator" and use_hint:
            src_norm = normalize_text(str(source or "observe")) or "observe"
            use_hint = src_norm in {"manual", "voice", "ai", "ai_spontaneous", "music", "vision", "curiosity"}
        target = list(target_hint) if use_hint and target_hint is not None else estimated_target
        target = normalize_training_target(robot, target, source=source, from_hint=bool(use_hint))
        
        threshold = 0.25 if robot == "Manipulator" else 0.015
        significant = mean_abs(target) > threshold
        src_low = str(source or "").lower()
        
        if src_low in {"music", "vision", "ai", "ai_spontaneous", "curiosity", "personality_audio", "personality_audio_startle"}:
            significant = True
        voice_age = safe_float(voice_ctx.get("text_age", 999.0), 999.0)
        voice_is_fresh = voice_age <= 1.25
        if voice_is_fresh and (voice_ctx.get("intent") != "none" or len(voice_ctx.get("norm", "")) >= 3):
            significant = True
        
        if safe_float(audio_feat[0] if audio_feat else 0.0) > 0.005:
            significant = True
        if vision_info.confidence > 0.20:
            significant = True
        if not significant:
            self.last_pose = pose_from_state(state)
            self.last_state_vector = telemetry_feat
            self.last_ts = now
            return False, None

        frame_path = ""
        if save_frame_every and save_frame_every > 0 and state.last_frame_pil is not None and self.records_written % max(1, save_frame_every) == 0:
            frame_path = str(FRAME_DIR / f"synrov_{int(now*1000)}.jpg")
            try:
                state.last_frame_pil.save(frame_path, quality=82)
            except Exception:
                frame_path = ""

        rec = SampleRecord(
            timestamp=now,
            robot=robot,
            source=source,
            simulation=None,
            leap_enabled=state.leap_enabled,
            voice_text=str(voice_ctx.get("text", "")) if voice_is_fresh else "",
            voice_norm=str(voice_ctx.get("norm", "")) if voice_is_fresh else "",
            voice_intent=str(voice_ctx.get("intent", "none")) if voice_is_fresh else "none",
            voice_confidence=safe_float(voice_ctx.get("conf", 0.0)) if voice_is_fresh else 0.0,
            telemetry_feat=telemetry_feat,
            synrov_feat=list(synrov_feat),
            webcam_feat=list(webcam_feat),
            audio_feat=list(audio_feat),
            vision_feat=vision_info.as_vector(),
            target=list(target),
            frame_path=frame_path,
        )
        self.dataset_path.parent.mkdir(parents=True, exist_ok=True)
        with self.dataset_path.open("a", encoding="utf-8") as f:
            f.write(json.dumps(rec.to_dict(), ensure_ascii=False) + "\n")
        self.records_written += 1
        self.last_pose = pose_from_state(state)
        self.last_state_vector = telemetry_feat
        self.last_ts = now
        return True, rec


def load_dataset(path: Path, robot: str) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    if not path.exists():
        return rows
    with path.open("r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                row = json.loads(line)
            except Exception:
                continue
            if row.get("robot") == robot:
                rows.append(row)
    return rows


def train_model(rows: List[Dict[str, Any]]) -> Dict[str, Any]:
    if np is None or joblib is None or ExtraTreesRegressor is None or train_test_split is None or r2_score is None:
        raise RuntimeError("Instale numpy, scikit-learn e joblib para treinar o modelo.")
    if not rows:
        raise RuntimeError("Dataset vazio para o robô selecionado.")

    rows, training_meta = prepare_training_rows(rows)
    if not rows:
        raise RuntimeError("Dataset sem linhas válidas para treino.")

    numeric_X: List[List[float]] = []
    voice_texts: List[str] = []
    y: List[List[float]] = []
    for row in rows:
        feat: List[float] = []
        feat.extend([safe_float(v) for v in row.get("telemetry_feat", [])])
        feat.extend([safe_float(v) for v in row.get("synrov_feat", [])])
        feat.extend([safe_float(v) for v in row.get("webcam_feat", [])])
        feat.extend([safe_float(v) for v in row.get("audio_feat", [])])
        feat.extend([safe_float(v) for v in row.get("vision_feat", [])])
        feat.extend(voice_vector(str(row.get("voice_intent", "none")), safe_float(row.get("voice_confidence", 0.0))))
        target = [safe_float(v) for v in row.get("target", [])]
        target = normalize_training_target(str(row.get("robot", "Manipulator")), target, source=str(row.get("source", "observe")), from_hint=False)
        if feat and target:
            numeric_X.append(feat)
            voice_texts.append(normalize_text(str(row.get("voice_text", ""))) or normalize_text(str(row.get("voice_norm", ""))) or "silencio")
            y.append(target)

    if len(numeric_X) < 20:
        raise RuntimeError("Poucas amostras úteis. Grave mais exemplos antes de treinar.")

    X_num = np.asarray(numeric_X, dtype=np.float32)
    y_arr = np.asarray(y, dtype=np.float32)

    voice_vectorizer = None
    voice_dim = 0
    if TfidfVectorizer is not None:
        voice_vectorizer = TfidfVectorizer(max_features=128, ngram_range=(1, 2), sublinear_tf=True, min_df=1)
        text_X = voice_vectorizer.fit_transform(voice_texts).toarray().astype(np.float32)
        voice_dim = text_X.shape[1]
        X = np.concatenate([X_num, text_X], axis=1)
    else:
        X = X_num

    x_train, x_test, y_train, y_test = train_test_split(X, y_arr, test_size=0.22, random_state=42)
    model = ExtraTreesRegressor(
        n_estimators=260,
        random_state=42,
        n_jobs=-1,
        min_samples_leaf=2,
        max_features="sqrt",
    )
    model.fit(x_train, y_train)
    pred = model.predict(x_test)
    score = float(r2_score(y_test, pred, multioutput="variance_weighted"))
    full_pred = model.predict(X)
    train_score = float(r2_score(y_arr, full_pred, multioutput="variance_weighted"))
    package = {
        "model": model,
        "voice_vectorizer": voice_vectorizer,
        "numeric_dim": int(X_num.shape[1]),
        "voice_dim": int(voice_dim),
        "target_dim": int(y_arr.shape[1]),
        "rows": int(len(rows)),
        "score": score,
        "train_score": train_score,
        "created_ts": time.time(),
        "feature_mean": X.mean(axis=0).astype(np.float32).tolist(),
        "feature_std": (X.std(axis=0).astype(np.float32) + 1e-6).tolist(),
        "target_abs_mean": float(np.mean(np.abs(y_arr)) + 1e-6),
        "training_source_counts": training_meta.get("source_counts", {}),
        "selected_rows": int(training_meta.get("selected_rows", len(rows))),
        "raw_rows": int(training_meta.get("raw_rows", len(rows))),
        "excluded_rows": int(training_meta.get("excluded_rows", 0)),
        "training_filter_note": training_meta.get("filter_note", "filtered_clean_sources"),
        "target_mode": MANIP_INCREMENTAL_TARGET_MODE if rows and normalize_robot_name(rows[0].get("robot", ""), "") == "Manipulator" else "control_increment",
    }
    return package


def build_inference_feature(package: Dict[str, Any], telemetry_feat: List[float], synrov_feat: List[float], webcam_feat: List[float], audio_feat: List[float], vision_feat: List[float], voice_text: str, voice_intent: str, voice_conf: float) -> List[float]:
    feat: List[float] = []
    feat.extend(list(telemetry_feat))
    feat.extend(list(synrov_feat))
    feat.extend(list(webcam_feat))
    feat.extend(list(audio_feat))
    feat.extend(list(vision_feat))
    feat.extend(voice_vector(voice_intent, voice_conf))
    numeric_dim = int(package.get("numeric_dim", len(feat)))
    if len(feat) < numeric_dim:
        feat.extend([0.0] * (numeric_dim - len(feat)))
    elif len(feat) > numeric_dim:
        feat = feat[:numeric_dim]
    if np is None:
        return feat
    vec = package.get("voice_vectorizer")
    if vec is not None:
        txt = normalize_text(voice_text) or "silencio"
        try:
            text_vec = vec.transform([txt]).toarray().astype(np.float32)[0].tolist()
        except Exception:
            text_vec = [0.0] * int(package.get("voice_dim", 0))
        feat.extend(text_vec)
    return feat


AI_SELF_GENERATED_SOURCES = {"ai", "ai_spontaneous", "ai_shadow", "shadow", "spontaneous"}


def prepare_training_rows(rows: List[Dict[str, Any]]) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    source_counts: Dict[str, int] = {}
    raw_rows = list(rows or [])
    filtered: List[Dict[str, Any]] = []
    for row in raw_rows:
        src = normalize_text(str(row.get("source", "observe") or "observe")) or "observe"
        source_counts[src] = source_counts.get(src, 0) + 1
        if src in AI_SELF_GENERATED_SOURCES:
            continue
        filtered.append(row)
    use_filtered = len(filtered) >= 20
    selected = filtered if use_filtered else raw_rows
    note = "filtered_clean_sources" if use_filtered else "fallback_all_rows"
    return selected, {
        "raw_rows": len(raw_rows),
        "selected_rows": len(selected),
        "excluded_rows": max(0, len(raw_rows) - len(filtered)) if use_filtered else 0,
        "source_counts": source_counts,
        "filter_note": note,
    }


def vector_l2(values: List[float]) -> float:
    if np is None:
        return math.sqrt(sum(float(v) * float(v) for v in values or []))
    arr = np.asarray(values or [], dtype=np.float32).reshape(-1)
    if arr.size == 0:
        return 0.0
    return float(np.linalg.norm(arr))


def cosine_similarity(a: List[float], b: List[float]) -> float:
    if np is None:
        aa = [float(v) for v in (a or [])]
        bb = [float(v) for v in (b or [])]
        if not aa or not bb or len(aa) != len(bb):
            return 0.0
        num = sum(x * y for x, y in zip(aa, bb))
        den = math.sqrt(sum(x * x for x in aa) * sum(y * y for y in bb))
        return float(num / den) if den > 1e-9 else 0.0
    aa = np.asarray(a or [], dtype=np.float32).reshape(-1)
    bb = np.asarray(b or [], dtype=np.float32).reshape(-1)
    if aa.size == 0 or bb.size == 0 or aa.size != bb.size:
        return 0.0
    den = float(np.linalg.norm(aa) * np.linalg.norm(bb))
    return float(np.dot(aa, bb) / den) if den > 1e-9 else 0.0


def clamp_infer_period_ms(value: Any, minimum: int = 50) -> int:
    return max(int(minimum), safe_int(value, minimum))


def compute_feature_familiarity(package: Dict[str, Any], feature: List[float]) -> float:
    if np is None:
        return 0.5
    mu = np.asarray(package.get("feature_mean", []), dtype=np.float32).reshape(-1)
    sigma = np.asarray(package.get("feature_std", []), dtype=np.float32).reshape(-1)
    x = np.asarray(feature or [], dtype=np.float32).reshape(-1)
    if mu.size == 0 or sigma.size == 0 or x.size != mu.size:
        return clamp(0.45 + 0.25 * max(0.0, safe_float(package.get("score", 0.0))), 0.0, 1.0)
    z = np.abs((x - mu) / (sigma + 1e-6))
    mean_z = float(np.mean(np.clip(z, 0.0, 4.0)))
    return clamp(1.0 - (mean_z / 2.6), 0.0, 1.0)


def compute_tree_agreement(package: Dict[str, Any], feature: List[float]) -> Tuple[float, Optional[float]]:
    if np is None:
        return 0.5, None
    model = package.get("model")
    x = np.asarray([feature], dtype=np.float32)
    predictions = []
    estimators = getattr(model, "estimators_", None)
    if estimators is not None:
        for est in list(estimators)[:32]:
            try:
                pred = np.asarray(est.predict(x), dtype=np.float32).reshape(-1)
                if pred.size:
                    predictions.append(pred)
            except Exception:
                continue
    if predictions:
        arr = np.stack(predictions, axis=0)
        std_mean = float(np.mean(np.std(arr, axis=0)))
        scale = max(0.15, safe_float(package.get("target_abs_mean", 0.5), 0.5))
        agreement = clamp(1.0 - (std_mean / (scale * 0.9 + 1e-6)), 0.0, 1.0)
        return agreement, std_mean
    score = safe_float(package.get("score", 0.0), 0.0)
    agreement = clamp(0.45 + 0.4 * max(0.0, score), 0.0, 1.0)
    return agreement, None


def estimate_prediction_confidence(package: Dict[str, Any], feature: List[float], prediction: List[float], telemetry_age: float = 0.0, frame_age: float = 0.0) -> Dict[str, float]:
    familiarity = compute_feature_familiarity(package, feature)
    agreement, raw_std = compute_tree_agreement(package, feature)
    quality = clamp((safe_float(package.get("score", 0.0), 0.0) + 0.15) / 1.0, 0.0, 1.0)
    freshness = clamp(1.0 - max(safe_float(telemetry_age, 0.0), 0.0) / 2.5, 0.15, 1.0)
    if safe_float(frame_age, 0.0) > 0.0:
        freshness = clamp(min(freshness, 1.0 - safe_float(frame_age, 0.0) / 3.0), 0.15, 1.0)
    magnitude = clamp(vector_l2([safe_float(v) for v in prediction]) / max(0.25, safe_float(package.get("target_abs_mean", 0.5), 0.5) * 3.0), 0.0, 1.0)
    confidence = clamp(0.40 * familiarity + 0.30 * agreement + 0.18 * quality + 0.08 * freshness + 0.04 * magnitude, 0.0, 1.0)
    return {
        "confidence": confidence,
        "familiarity": familiarity,
        "agreement": agreement,
        "quality": quality,
        "freshness": freshness,
        "magnitude": magnitude,
        "tree_std": safe_float(raw_std, 0.0),
    }


def spontaneity_offsets(robot: str, dims: int, now: float, confidence: float, strength: float = 0.15) -> List[float]:
    strength = clamp(strength, 0.0, 1.0)
    gate = clamp((confidence - 0.62) / 0.30, 0.0, 1.0)
    amp = strength * gate
    if amp <= 1e-6:
        return [0.0] * max(0, dims)
    phases = [0.0, 0.9, 1.7, 2.6, 3.3, 4.1, 5.0]
    freqs = [0.45, 0.62, 0.55, 0.71, 0.58, 0.77, 0.49]
    if robot == "Manipulator":
        scales = [1.6, 0.8, 0.7, 0.45, 0.55, 0.65, 0.35]
    elif robot == "Vehicle":
        scales = [0.05, 0.06, 0.03, 0.03]
    else:
        scales = [0.04, 0.04, 0.03, 0.03, 0.03, 0.04]
    offsets: List[float] = []
    for i in range(dims):
        scale = scales[i] if i < len(scales) else scales[-1]
        phase = phases[i] if i < len(phases) else (0.5 * i)
        freq = freqs[i] if i < len(freqs) else (0.41 + 0.05 * i)
        offsets.append(float(math.sin(now * freq + phase) * scale * amp))
    return offsets


def should_enable_spontaneity(task: Dict[str, Any], confidence: float) -> bool:
    if not bool(task.get("allow_spontaneity", False)):
        return False
    if bool(task.get("shadow_mode", False)):
        return False
    if confidence < max(0.62, safe_float(task.get("min_confidence", 0.58), 0.58) + 0.06):
        return False
    if safe_float(task.get("recent_external_age", 999.0), 999.0) < 1.1:
        return False
    if safe_float(task.get("vision_confidence", 0.0), 0.0) > 0.55:
        return False
    voice_intent = str(task.get("voice_intent", "none") or "none")
    if voice_intent not in {"none", "music_follow"}:
        return False
    return True


def blend_predictions(base: List[float], offsets: List[float]) -> List[float]:
    out: List[float] = []
    for i, value in enumerate(base):
        out.append(safe_float(value) + safe_float(offsets[i] if i < len(offsets) else 0.0))
    return out


def observed_shadow_vector(robot: str, state: SynROVState, base_pose: Dict[str, float], base_telem: List[float]) -> List[float]:
    if robot == "Manipulator":
        current = pose_from_state(state)
        return [safe_float(current.get(k, 0.0)) - safe_float(base_pose.get(k, 0.0)) for k in MANIP_KEYS]
    current = [safe_float(v) for v in DatasetCollector(Path(DATASET_PATH))._telemetry_vector(state)]
    prev = [safe_float(v) for v in (base_telem or [])]
    if robot == "Vehicle":
        x_delta = (current[7] if len(current) > 7 else 0.0) - (prev[7] if len(prev) > 7 else 0.0)
        z_delta = (current[8] if len(current) > 8 else 0.0) - (prev[8] if len(prev) > 8 else 0.0)
        yaw_delta = (current[9] if len(current) > 9 else 0.0) - (prev[9] if len(prev) > 9 else 0.0)
        cam_pan_delta = (current[10] if len(current) > 10 else 0.0) - (prev[10] if len(prev) > 10 else 0.0)
        cam_tilt_delta = (current[11] if len(current) > 11 else 0.0) - (prev[11] if len(prev) > 11 else 0.0)
        return [x_delta + z_delta, yaw_delta / 30.0, cam_pan_delta / 90.0, cam_tilt_delta / 45.0]
    dx = (current[12] if len(current) > 12 else 0.0) - (prev[12] if len(prev) > 12 else 0.0)
    dy = (current[13] if len(current) > 13 else 0.0) - (prev[13] if len(prev) > 13 else 0.0)
    dz = (current[14] if len(current) > 14 else 0.0) - (prev[14] if len(prev) > 14 else 0.0)
    yaw_d = (current[15] if len(current) > 15 else 0.0) - (prev[15] if len(prev) > 15 else 0.0)
    pitch_d = (current[16] if len(current) > 16 else 0.0) - (prev[16] if len(prev) > 16 else 0.0)
    roll_d = (current[17] if len(current) > 17 else 0.0) - (prev[17] if len(prev) > 17 else 0.0)
    return [dy, yaw_d / 60.0, pitch_d / 60.0, roll_d / 60.0, dx, dz]


def evaluate_shadow_score(predicted: List[float], observed: List[float]) -> Tuple[float, float, float]:
    pred = [safe_float(v) for v in (predicted or [])]
    obs = [safe_float(v) for v in (observed or [])]
    if not pred or not obs or len(pred) != len(obs):
        return 0.0, 0.0, 0.0
    cos = cosine_similarity(pred, obs)
    direction = clamp((cos + 1.0) * 0.5, 0.0, 1.0)
    mag_pred = vector_l2(pred)
    mag_obs = vector_l2(obs)
    if mag_pred < 1e-6 and mag_obs < 1e-6:
        magnitude = 1.0
    else:
        magnitude = clamp(1.0 - abs(mag_pred - mag_obs) / max(mag_pred, mag_obs, 1e-6), 0.0, 1.0)
    score = clamp(0.72 * direction + 0.28 * magnitude, 0.0, 1.0)
    return score, direction, magnitude


