class MultimodalAutoLearnStudio:
    def __init__(self, root: tk.Tk) -> None:
        self.root = root
        self.root.title(APP_NAME)
        self.root.geometry("1180x760")
        self.root.minsize(1020, 700)
        self.root.configure(bg="#e9ecef")

        self.uri_var = tk.StringVar(value=DEFAULT_URI)
        self.robot_var = tk.StringVar(value="Manipulator")
        self.status_var = tk.StringVar(value="Desconectado")
        self.voice_var = tk.StringVar(value="—")
        self.intent_var = tk.StringVar(value="none")
        self.object_var = tk.StringVar(value="objeto: —")
        self.dataset_var = tk.StringVar(value=str(DATASET_PATH))
        self.model_var = tk.StringVar(value=str(MODEL_DIR / "synrov_multimodal_model_Manipulator.joblib"))
        self.target_color_var = tk.StringVar(value="green")  # Always English canonical
        # _color_display_var drives the combobox; it shows PT or EN based on language.
        # A trace keeps target_color_var in sync (always English).
        self._color_display_var = tk.StringVar(value="verde")
        self._color_combos: List[Any] = []

        self._color_sync_lock: bool = False  # re-entrancy guard

        def _on_color_display_change(*_args: Any) -> None:
            if self._color_sync_lock:
                return
            self._color_sync_lock = True
            try:
                canonical = _color_canonical(self._color_display_var.get())
                if self.target_color_var.get() != canonical:
                    self.target_color_var.set(canonical)
            finally:
                self._color_sync_lock = False

        self._color_display_var.trace_add("write", _on_color_display_change)
        self.webcam_index_var = tk.IntVar(value=0)
        self.retrain_every_var = tk.IntVar(value=80)
        self.min_train_rows_var = tk.IntVar(value=180)
        self.infer_period_ms = tk.IntVar(value=180)
        self.voice_hold_var = tk.DoubleVar(value=8.0)
        self.ai_gain_var = tk.DoubleVar(value=0.65)
        self.music_gain_var = tk.DoubleVar(value=0.55)
        self.object_gain_var = tk.DoubleVar(value=0.60)
        self.auto_collect_var = tk.BooleanVar(value=True)
        self.auto_retrain_var = tk.BooleanVar(value=True)
        self.ai_enabled_var = tk.BooleanVar(value=True)
        self.direct_voice_var = tk.BooleanVar(value=True)
        self.music_follow_var = tk.BooleanVar(value=True)
        self.object_follow_var = tk.BooleanVar(value=True)
        self.webcam_enabled_var = tk.BooleanVar(value=False)
        self.safe_auto_var = tk.BooleanVar(value=False)

        self.event_queue: "queue.Queue[Tuple[str, Any]]" = queue.Queue()
        self.bridge = SynROVBridge(self.event_queue)
        self.voice_parser = RichVoiceParser()
        self.voice_engine = VoiceAudioEngine(self.voice_parser, self.robot_var.get)
        self.webcam = WebcamSource()
        self.collector = DatasetCollector(Path(self.dataset_var.get()))
        self.model_packages: Dict[str, Dict[str, Any]] = {}
        self.training_thread: Optional[threading.Thread] = None
        self.training_info = {"rows": 0, "score": 0.0, "train_score": 0.0, "training": False, "last_train_rows": 0}

        self.preview_photo = None
        self.webcam_photo = None
        self.last_preview_hash = 0
        self.last_webcam_hash = 0
        self.last_vision = VisionInfo()
        self.last_command_ts = 0.0
        self.last_command_target: Optional[List[float]] = None
        self.last_command_source = "none"
        self.last_manual_cmd = ""
        self.last_ai_step = 0.0
        self.last_save_notice = 0.0
        self.last_handled_voice_ts = 0.0
        self._realtime_slider_after_id = None
        self._realtime_slider_pending_group = None
        self._manual_slider_send_suspended = False
        self._manual_slider_sync_idle_s = MANUAL_SLIDER_SYNC_IDLE_S
        self._manual_manip_active_until = {k: 0.0 for k in MANIP_KEYS}
        self._manual_vehicle_active_until = {k: 0.0 for k in VEHICLE_KEYS}
        self._manual_drone_active_until = {k: 0.0 for k in DRONE_KEYS}
