    def _build_styles(self) -> None:
        style = ttk.Style()
        try:
            style.theme_use("clam")
        except Exception:
            pass
        style.configure("TFrame", background="#e9ecef")
        style.configure("Card.TFrame", background="#ffffff", relief="flat")
        style.configure("Title.TLabel", font=("Segoe UI", 13, "bold"), background="#ffffff", foreground="#1f2d3d")
        style.configure("Body.TLabel", font=("Segoe UI", 9), background="#ffffff", foreground="#334")
        style.configure("Info.TLabel", font=("Segoe UI", 9, "bold"), background="#ffffff", foreground="#0d6efd")
        style.configure("OK.TLabel", font=("Segoe UI", 9, "bold"), background="#ffffff", foreground="#198754")
        style.configure("Warn.TLabel", font=("Segoe UI", 9, "bold"), background="#ffffff", foreground="#fd7e14")
        style.configure("Danger.TLabel", font=("Segoe UI", 9, "bold"), background="#ffffff", foreground="#dc3545")
        style.configure("TButton", padding=5)
        style.configure("Small.TButton", padding=3)
        style.configure("TNotebook", background="#e9ecef")
        style.configure("TNotebook.Tab", padding=(8, 4))

