    def _build_policy_card(self, parent) -> None:
        ttk.Checkbutton(parent, text="Voz simbólica direta", variable=self.direct_voice_var).pack(anchor="w", pady=2)
        ttk.Checkbutton(parent, text="Seguir música/ritmo", variable=self.music_follow_var).pack(anchor="w", pady=2)
        ttk.Checkbutton(parent, text="Assistência por objeto", variable=self.object_follow_var).pack(anchor="w", pady=2)
        ttk.Checkbutton(parent, text="Bloquear comandos automáticos", variable=self.safe_auto_var).pack(anchor="w", pady=2)
        row1 = ttk.Frame(parent, style="Card.TFrame")
        row1.pack(fill="x", pady=(6, 0))
        ttk.Label(row1, text="Cor alvo:").pack(side="left")
        self._make_color_combo(row1).pack(side="left", padx=6)
        ttk.Label(row1, text="Hold voz(s):").pack(side="left")
        ttk.Spinbox(row1, textvariable=self.voice_hold_var, from_=2, to=20, width=5, increment=1.0).pack(side="left", padx=4)
        for label, var in [("ganho IA", self.ai_gain_var), ("ganho música", self.music_gain_var), ("ganho objeto", self.object_gain_var)]:
            row = ttk.Frame(parent, style="Card.TFrame")
            row.pack(fill="x", pady=(4, 0))
            ttk.Label(row, text=label).pack(side="left")
            ttk.Scale(row, from_=0.0, to=2.0, variable=var).pack(side="left", fill="x", expand=True, padx=6)
            ttk.Label(row, textvariable=tk.StringVar(value="")).pack(side="left")
        row2 = ttk.Frame(parent, style="Card.TFrame")
        row2.pack(fill="x", pady=(6, 0))
        ttk.Label(row2, text="Período IA (ms):").pack(side="left")
        ttk.Spinbox(row2, textvariable=self.infer_period_ms, from_=50, to=2000, width=6, increment=20).pack(side="left", padx=4)
        ttk.Button(row2, text="HOME braço", command=self.home_manipulator).pack(side="left", padx=6)

    def _build_learning_card(self, parent) -> None:
        row = ttk.Frame(parent, style="Card.TFrame")
        row.pack(fill="x", pady=(6, 4))
        ttk.Label(row, text="Dataset:").pack(side="left")
        ttk.Entry(row, textvariable=self.dataset_var).pack(side="left", fill="x", expand=True, padx=4)
        ttk.Button(row, text="...", width=3, command=self.choose_dataset).pack(side="left")
        row2 = ttk.Frame(parent, style="Card.TFrame")
        row2.pack(fill="x", pady=4)
        ttk.Label(row2, text="min linhas").pack(side="left")
        ttk.Spinbox(row2, textvariable=self.min_train_rows_var, from_=40, to=5000, width=7).pack(side="left", padx=4)
        ttk.Label(row2, text="retreino a cada").pack(side="left")
        ttk.Spinbox(row2, textvariable=self.retrain_every_var, from_=20, to=1000, width=7).pack(side="left", padx=4)
        ttk.Label(row2, text="linhas novas").pack(side="left")
        row3 = ttk.Frame(parent, style="Card.TFrame")
        row3.pack(fill="x", pady=4)
