    # -----------------------------------------------------------------
    # Color display helpers — keep target_color_var in English canonical
    # and update all registered comboboxes when the language changes.
    # -----------------------------------------------------------------
    def _update_color_display(self, lang: Optional[str] = None) -> None:
        """Sync color display var and all color comboboxes to *lang*.

        Uses _color_sync_lock to break any trace→update→trace feedback loop.
        """
        if getattr(self, "_color_sync_lock", False):
            return
        try:
            self._color_sync_lock = True
            if lang is None:
                lang = getattr(getattr(self, "lang", None), "get", lambda: "pt")()
            new_values = _color_display_values(lang)
            canonical = _color_canonical(self.target_color_var.get())
            new_display = _color_display(canonical, lang)
            # Update combobox values lists first, then the selected value.
            for combo in self._color_combos:
                try:
                    combo["values"] = new_values
                except Exception:
                    pass
            if self._color_display_var.get() != new_display:
                self._color_display_var.set(new_display)
        except Exception:
            pass
        finally:
            self._color_sync_lock = False

    def _make_color_combo(self, parent: Any, **kw: Any) -> Any:
        """Build a language-aware color combobox bound to _color_display_var."""
        try:
            lang = getattr(getattr(self, "lang", None), "get", lambda: "pt")()
        except Exception:
            lang = "pt"
        combo = ttk.Combobox(
            parent,
            state="readonly",
            width=kw.pop("width", 10),
            values=_color_display_values(lang),
            textvariable=self._color_display_var,
            **kw,
        )
        self._color_combos.append(combo)
        return combo

