def ui_tr(lang: str, key: str) -> str:
    return UI_TR.get(lang, UI_TR["en"]).get(key, key)


class CompactMultimodalAutoLearnStudio(MultimodalAutoLearnStudio):
    def __init__(self, root: tk.Tk) -> None:
        self.lang = tk.StringVar(master=root, value="en")
        super().__init__(root)
        self.root.title(ui_tr(self.lang.get(), "title"))
        self.root.geometry("1040x680")
        self.root.minsize(920, 620)
        self._apply_language()
        self._show_robot_panel()

    def _build_styles(self) -> None:
        style = ttk.Style()
        try:
            style.theme_use("clam")
        except Exception:
            pass
        style.configure("TFrame", background="#e9ecef")
        style.configure("Card.TFrame", background="#ffffff", relief="flat")
        style.configure("Title.TLabel", font=("Segoe UI", 10, "bold"), background="#ffffff", foreground="#1f2d3d")
        style.configure("Body.TLabel", font=("Segoe UI", 8), background="#ffffff", foreground="#334")
        style.configure("Info.TLabel", font=("Segoe UI", 8, "bold"), background="#ffffff", foreground="#0d6efd")
        style.configure("OK.TLabel", font=("Segoe UI", 8, "bold"), background="#ffffff", foreground="#198754")
        style.configure("Warn.TLabel", font=("Segoe UI", 8, "bold"), background="#ffffff", foreground="#fd7e14")
        style.configure("Danger.TLabel", font=("Segoe UI", 8, "bold"), background="#ffffff", foreground="#dc3545")
        style.configure("TButton", padding=3)
        style.configure("Small.TButton", padding=2)
        style.configure("TNotebook", background="#e9ecef")
        style.configure("TNotebook.Tab", padding=(6, 3))

    def _make_card(self, parent, key: str):
        frame = ttk.Frame(parent, style="Card.TFrame", padding=6)
        title = ttk.Label(frame, text=ui_tr(self.lang.get(), key), style="Title.TLabel")
        title.pack(anchor="w")
        self._i18n_card_titles[key] = title
        return frame

    def _build_ui(self) -> None:
        tr = lambda key: command_center_tr(self.lang.get(), key)
        self._i18n_card_titles = {}
        self.root.configure(bg="#e9ecef")

        top = ttk.Frame(self.root, padding=(6, 6, 6, 4))
        top.pack(fill="x")
        self.btn_connect = ttk.Button(top, text=ui_tr(self.lang.get(), "connect"), command=self.connect)
        self.btn_connect.pack(side="left")
        self.btn_disconnect = ttk.Button(top, text=ui_tr(self.lang.get(), "disconnect"), command=self.disconnect, style="Small.TButton")
        self.btn_disconnect.pack(side="left", padx=4)

        self.lbl_uri = ttk.Label(top, text="URI:")
        self.lbl_uri.pack(side="left", padx=(10, 3))
        ttk.Entry(top, textvariable=self.uri_var, width=24).pack(side="left")

        self.lbl_robot = ttk.Label(top, text=ui_tr(self.lang.get(), "robot") + ":")
        self.lbl_robot.pack(side="left", padx=(10, 3))
        robot_box = ttk.Combobox(top, state="readonly", width=11, values=["Manipulator", "Vehicle", "Drone"], textvariable=self.robot_var)
        robot_box.pack(side="left")
        robot_box.bind("<<ComboboxSelected>>", lambda e: self._apply_robot_defaults())

        self.lbl_lang = ttk.Label(top, text=ui_tr(self.lang.get(), "lang") + ":")
        self.lbl_lang.pack(side="left", padx=(10, 3))
        lang_box = ttk.Combobox(top, state="readonly", width=5, values=["en", "pt"], textvariable=self.lang)
        lang_box.pack(side="left")
        lang_box.bind("<<ComboboxSelected>>", lambda e: self._apply_language())

        self.chk_ai = ttk.Label(top, text=ui_tr(self.lang.get(), "ai"))
        self.chk_ai.pack(side="left", padx=(10, 4))
        self.chk_collect = ttk.Checkbutton(top, text=ui_tr(self.lang.get(), "collect"), variable=self.auto_collect_var, command=self._toggle_collect)
        self.chk_collect.pack(side="left", padx=4)
        self.chk_retrain = ttk.Checkbutton(top, text=ui_tr(self.lang.get(), "retrain"), variable=self.auto_retrain_var)
        self.chk_retrain.pack(side="left", padx=4)
        self.btn_mic = ttk.Button(top, text=ui_tr(self.lang.get(), "start_mic"), command=self.toggle_voice)
        self.btn_mic.pack(side="right")

        body = ttk.Frame(self.root, padding=(6, 0, 6, 6))
        body.pack(fill="both", expand=True)
        body.columnconfigure(0, weight=0, minsize=320)
        body.columnconfigure(1, weight=1)
        body.rowconfigure(0, weight=1)

        left = ttk.Frame(body)
        left.grid(row=0, column=0, sticky="nsew", padx=(0, 6))
        right = ttk.Frame(body)
        right.grid(row=0, column=1, sticky="nsew")
        right.rowconfigure(0, weight=1)
        right.columnconfigure(0, weight=1)

        status_card = self._make_card(left, "status")
        status_card.pack(fill="x", pady=(0, 6))
        self.status_label = ttk.Label(status_card, textvariable=self.status_var, style="Info.TLabel", wraplength=300)
        self.status_label.pack(anchor="w")
        self.meta_label = ttk.Label(status_card, text="sim=OFF | leap=OFF | telem=0 | frames=0", style="Body.TLabel")
        self.meta_label.pack(anchor="w", pady=(2, 4))
        self.voice_label = ttk.Label(status_card, textvariable=self.voice_var, style="Body.TLabel", wraplength=300)
        self.voice_label.pack(anchor="w", pady=1)
        self.intent_label = ttk.Label(status_card, textvariable=self.intent_var, style="Info.TLabel", wraplength=300)
        self.intent_label.pack(anchor="w", pady=1)
        self.obj_label = ttk.Label(status_card, textvariable=self.object_var, style="Body.TLabel", wraplength=300)
        self.obj_label.pack(anchor="w", pady=(1, 4))
        meter_row = ttk.Frame(status_card, style="Card.TFrame")
        meter_row.pack(fill="x")
        self.lbl_audio = ttk.Label(meter_row, text=ui_tr(self.lang.get(), "audio"))
        self.lbl_audio.pack(side="left")
        self.meter = ttk.Progressbar(meter_row, maximum=100)
        self.meter.pack(side="left", fill="x", expand=True, padx=6)
        self.score_label = ttk.Label(meter_row, text="R²: —", style="Info.TLabel")
        self.score_label.pack(side="left")

        preview_card = self._make_card(left, "vision")
        preview_card.pack(fill="both", expand=True)
        chip_row = ttk.Frame(preview_card, style="Card.TFrame")
        chip_row.pack(fill="x", pady=(2, 4))
        self.robot_chip = ttk.Label(chip_row, text="Manipulator", style="Body.TLabel")
        self.robot_chip.pack(side="left")
        self.sim_chip = ttk.Label(chip_row, text="telem 0", style="Body.TLabel")
        self.sim_chip.pack(side="left", padx=6)
        self.frame_chip = ttk.Label(chip_row, text="frames 0", style="Body.TLabel")
        self.frame_chip.pack(side="left")
        self.preview_panel = tk.Label(preview_card, bg="#d9dee3", width=300, height=170, text=ui_tr(self.lang.get(), "preview_wait"))
        self.preview_panel.pack(fill="x", pady=(2, 4))
        self.webcam_panel = tk.Label(preview_card, bg="#eef1f4", width=300, height=95, text=ui_tr(self.lang.get(), "webcam_wait"))
        self.webcam_panel.pack(fill="x")

        self.notebook = ttk.Notebook(right)
        self.notebook.grid(row=0, column=0, sticky="nsew")

        self.tab_control = ttk.Frame(self.notebook, padding=6)
        self.tab_multi = ttk.Frame(self.notebook, padding=6)
        self.tab_learning = ttk.Frame(self.notebook, padding=6)
        self.tab_log = ttk.Frame(self.notebook, padding=6)
        self.tab_help = ttk.Frame(self.notebook, padding=6)
        self.notebook.add(self.tab_control, text=ui_tr(self.lang.get(), "control"))
        self.notebook.add(self.tab_multi, text=ui_tr(self.lang.get(), "multimodal"))
        self.notebook.add(self.tab_learning, text=ui_tr(self.lang.get(), "learning"))
        self.notebook.add(self.tab_log, text=ui_tr(self.lang.get(), "log"))
        self.notebook.add(self.tab_help, text=ui_tr(self.lang.get(), "help"))

        self._build_control_tab_compact()
        self._build_multimodal_tab_compact()
        self._build_learning_tab_compact()
        self._build_log_tab_compact()
        self._build_help_tab_compact()

    def _build_control_tab_compact(self) -> None:
        self.tab_control.columnconfigure(0, weight=1)
        voice_card = self._make_card(self.tab_control, "voice_input")
        voice_card.grid(row=0, column=0, sticky="ew", pady=(0, 6))
        row1 = ttk.Frame(voice_card, style="Card.TFrame")
        row1.pack(fill="x", pady=(2, 4))
        self.voice_entry = ttk.Entry(row1)
        self.voice_entry.pack(side="left", fill="x", expand=True)
        self.voice_entry.bind("<Return>", lambda e: self.send_voice_text())
        self.btn_send_voice = ttk.Button(row1, text=ui_tr(self.lang.get(), "send_text"), command=self.send_voice_text)
        self.btn_send_voice.pack(side="left", padx=(4, 0))
        row2 = ttk.Frame(voice_card, style="Card.TFrame")
        row2.pack(fill="x")
        self.btn_voice_toggle = ttk.Button(row2, text=ui_tr(self.lang.get(), "start_mic"), command=self.toggle_voice)
        self.btn_voice_toggle.pack(side="left")
        self.chk_direct_voice = ttk.Checkbutton(row2, text=ui_tr(self.lang.get(), "direct_voice"), variable=self.direct_voice_var)
        self.chk_direct_voice.pack(side="left", padx=(8, 0))
        self.voice_info_compact = ttk.Label(voice_card, text="-", style="Body.TLabel", wraplength=640)
        self.voice_info_compact.pack(anchor="w", pady=(4, 0))

        manual_card = self._make_card(self.tab_control, "manual")
        manual_card.grid(row=1, column=0, sticky="nsew")
        manual_card.columnconfigure(0, weight=1)
        self.manual_container = ttk.Frame(manual_card, style="Card.TFrame")
        self.manual_container.pack(fill="both", expand=True)
        self.manip_frame = ttk.Frame(self.manual_container, style="Card.TFrame")
        self.vehicle_frame = ttk.Frame(self.manual_container, style="Card.TFrame")
        self.drone_frame = ttk.Frame(self.manual_container, style="Card.TFrame")
        for fr in (self.manip_frame, self.vehicle_frame, self.drone_frame):
            fr.place(relx=0, rely=0, relwidth=1, relheight=1)
        self._build_compact_manip_panel()
        self._build_compact_vehicle_panel()
        self._build_compact_drone_panel()

    def _add_slider_compact(self, parent, row: int, col: int, label: str, var: tk.DoubleVar, lo: float, hi: float, res: float) -> None:
        cell = ttk.Frame(parent, style="Card.TFrame")
        cell.grid(row=row, column=col, sticky="nsew", padx=3, pady=2)
        ttk.Label(cell, text=label, style="Body.TLabel").pack(anchor="w")
        line = ttk.Frame(cell, style="Card.TFrame")
        line.pack(fill="x")
        sc = tk.Scale(line, variable=var, from_=lo, to=hi, resolution=res, orient="horizontal", showvalue=False, length=180, bg="#f7f8fa", highlightthickness=0)
        sc.pack(side="left", fill="x", expand=True)
        ttk.Entry(line, textvariable=var, width=7).pack(side="left", padx=(4, 0))

    def _build_compact_manip_panel(self) -> None:
        grid = ttk.Frame(self.manip_frame, style="Card.TFrame")
        grid.pack(fill="both", expand=True)
        for c in range(2):
            grid.columnconfigure(c, weight=1)
        specs = [
            ("Base", self.manual_manip["base"], 0, 359, 1),
            ("Upper", self.manual_manip["upper"], 0, 180, 1),
            ("Fore", self.manual_manip["fore"], 0, 180, 1),
            ("Fore roll", self.manual_manip["forearm_roll"], 0, 180, 1),
            ("Wrist pitch", self.manual_manip["wrist_pitch"], 0, 180, 1),
            ("Wrist rot", self.manual_manip["wrist_rot"], 0, 180, 1),
            ("Grip", self.manual_manip["grip"], 0, 180, 1),
        ]
        for i, spec in enumerate(specs):
            self._add_slider_compact(grid, i // 2, i % 2, *spec)
        btns = ttk.Frame(self.manip_frame, style="Card.TFrame")
        btns.pack(fill="x", pady=(4, 0))
        ttk.Button(btns, text="Send ARMJ", command=self.send_manual_manipulator).pack(side="left")
        self.btn_home_arm = ttk.Button(btns, text=ui_tr(self.lang.get(), "home_arm"), command=self.home_manipulator)
        self.btn_home_arm.pack(side="left", padx=6)

    def _build_compact_vehicle_panel(self) -> None:
        grid = ttk.Frame(self.vehicle_frame, style="Card.TFrame")
        grid.pack(fill="both", expand=True)
        for c in range(2):
            grid.columnconfigure(c, weight=1)
        specs = [
            ("Throttle", self.manual_vehicle["throttle"], -1, 1, 0.01),
            ("Steer", self.manual_vehicle["steer"], -1, 1, 0.01),
            ("Cam pan", self.manual_vehicle["cam_pan"], -90, 90, 1),
            ("Cam tilt", self.manual_vehicle["cam_tilt"], -45, 45, 1),
        ]
        for i, spec in enumerate(specs):
            self._add_slider_compact(grid, i // 2, i % 2, *spec)
        btns = ttk.Frame(self.vehicle_frame, style="Card.TFrame")
        btns.pack(fill="x", pady=(4, 0))
        ttk.Button(btns, text="Send MOVE", command=self.send_manual_vehicle).pack(side="left")
        ttk.Button(btns, text="STOP", command=lambda: self.bridge.send_vehicle(0, 0)).pack(side="left", padx=6)

    def _build_compact_drone_panel(self) -> None:
        grid = ttk.Frame(self.drone_frame, style="Card.TFrame")
        grid.pack(fill="both", expand=True)
        for c in range(2):
            grid.columnconfigure(c, weight=1)
        specs = [
            ("Throttle", self.manual_drone["throttle"], -1, 1, 0.01),
            ("Yaw", self.manual_drone["yaw"], -1, 1, 0.01),
            ("Pitch", self.manual_drone["pitch"], -1, 1, 0.01),
            ("Roll", self.manual_drone["roll"], -1, 1, 0.01),
            ("Strafe", self.manual_drone["strafe"], -1, 1, 0.01),
            ("Forward", self.manual_drone["forward"], -1, 1, 0.01),
        ]
        for i, spec in enumerate(specs):
            self._add_slider_compact(grid, i // 2, i % 2, *spec)
        btns = ttk.Frame(self.drone_frame, style="Card.TFrame")
        btns.pack(fill="x", pady=(4, 0))
        ttk.Button(btns, text="Send FLY", command=self.send_manual_drone).pack(side="left")
        ttk.Button(btns, text="TAKEOFF", command=self.takeoff_drone).pack(side="left", padx=6)
        ttk.Button(btns, text="LAND", command=self.land_drone).pack(side="left")

    def _build_multimodal_tab_compact(self) -> None:
        self.tab_multi.columnconfigure(0, weight=1)
        card1 = self._make_card(self.tab_multi, "autonomy")
        card1.grid(row=0, column=0, sticky="ew", pady=(0, 6))
        self.chk_direct_voice2 = ttk.Checkbutton(card1, text=ui_tr(self.lang.get(), "direct_voice"), variable=self.direct_voice_var)
        self.chk_direct_voice2.pack(anchor="w", pady=1)
        self.chk_music = ttk.Checkbutton(card1, text=ui_tr(self.lang.get(), "follow_music"), variable=self.music_follow_var)
        self.chk_music.pack(anchor="w", pady=1)
        self.chk_object = ttk.Checkbutton(card1, text=ui_tr(self.lang.get(), "follow_object"), variable=self.object_follow_var)
        self.chk_object.pack(anchor="w", pady=1)
        self.chk_safe = ttk.Checkbutton(card1, text=ui_tr(self.lang.get(), "safe_auto"), variable=self.safe_auto_var)
        self.chk_safe.pack(anchor="w", pady=(1, 4))

        row = ttk.Frame(card1, style="Card.TFrame")
        row.pack(fill="x", pady=2)
        self.lbl_target_color = ttk.Label(row, text=ui_tr(self.lang.get(), "target_color"))
        self.lbl_target_color.pack(side="left")
        self._make_color_combo(row).pack(side="left", padx=6)
        self.lbl_voice_hold = ttk.Label(row, text=ui_tr(self.lang.get(), "voice_hold"))
        self.lbl_voice_hold.pack(side="left", padx=(8, 2))
        ttk.Spinbox(row, textvariable=self.voice_hold_var, from_=2, to=20, width=5, increment=1.0).pack(side="left")

        for key, var in [("ai_gain", self.ai_gain_var), ("music_gain", self.music_gain_var), ("object_gain", self.object_gain_var)]:
            r = ttk.Frame(card1, style="Card.TFrame")
            r.pack(fill="x", pady=2)
            lbl = ttk.Label(r, text=ui_tr(self.lang.get(), key))
            lbl.pack(side="left")
            setattr(self, f"lbl_{key}", lbl)
            ttk.Scale(r, from_=0.0, to=2.0, variable=var).pack(side="left", fill="x", expand=True, padx=6)
            ttk.Label(r, textvariable=tk.StringVar(value="")).pack(side="left")

        r2 = ttk.Frame(card1, style="Card.TFrame")
        r2.pack(fill="x", pady=2)
        self.lbl_infer_period = ttk.Label(r2, text=ui_tr(self.lang.get(), "infer_period"))
        self.lbl_infer_period.pack(side="left")
        ttk.Spinbox(r2, textvariable=self.infer_period_ms, from_=50, to=2000, width=6, increment=20).pack(side="left", padx=6)
        self.btn_home_arm2 = ttk.Button(r2, text=ui_tr(self.lang.get(), "home_arm"), command=self.home_manipulator)
        self.btn_home_arm2.pack(side="left")

        card2 = self._make_card(self.tab_multi, "dataset_model")
        card2.grid(row=1, column=0, sticky="nsew")
        rowd = ttk.Frame(card2, style="Card.TFrame")
        rowd.pack(fill="x", pady=2)
        self.lbl_dataset = ttk.Label(rowd, text=ui_tr(self.lang.get(), "dataset"))
        self.lbl_dataset.pack(side="left")
        ttk.Entry(rowd, textvariable=self.dataset_var).pack(side="left", fill="x", expand=True, padx=4)
        self.btn_choose_dataset = ttk.Button(rowd, text=ui_tr(self.lang.get(), "choose"), width=8, command=self.choose_dataset)
        self.btn_choose_dataset.pack(side="left")

        rowm = ttk.Frame(card2, style="Card.TFrame")
        rowm.pack(fill="x", pady=2)
        self.lbl_min_rows = ttk.Label(rowm, text=ui_tr(self.lang.get(), "min_rows"))
        self.lbl_min_rows.pack(side="left")
        ttk.Spinbox(rowm, textvariable=self.min_train_rows_var, from_=40, to=5000, width=6).pack(side="left", padx=4)
        self.lbl_retrain_every = ttk.Label(rowm, text=ui_tr(self.lang.get(), "retrain_every"))
        self.lbl_retrain_every.pack(side="left", padx=(8, 2))
        ttk.Spinbox(rowm, textvariable=self.retrain_every_var, from_=20, to=1000, width=6).pack(side="left", padx=4)
        self.lbl_new_rows = ttk.Label(rowm, text=ui_tr(self.lang.get(), "new_rows"))
        self.lbl_new_rows.pack(side="left")

        rowb = ttk.Frame(card2, style="Card.TFrame")
        rowb.pack(fill="x", pady=2)
        self.btn_train_now = ttk.Button(rowb, text=ui_tr(self.lang.get(), "train_now"), command=self.train_now)
        self.btn_train_now.pack(side="left")
        self.btn_save_model = ttk.Button(rowb, text=ui_tr(self.lang.get(), "save_model"), command=self.save_model)
        self.btn_save_model.pack(side="left", padx=4)
        self.btn_load_model = ttk.Button(rowb, text=ui_tr(self.lang.get(), "load_model"), command=self.load_model)
        self.btn_load_model.pack(side="left")

        roww = ttk.Frame(card2, style="Card.TFrame")
        roww.pack(fill="x", pady=2)
        self.chk_webcam = ttk.Checkbutton(roww, text=ui_tr(self.lang.get(), "webcam"), variable=self.webcam_enabled_var, command=self.toggle_webcam)
        self.chk_webcam.pack(side="left")
        ttk.Spinbox(roww, textvariable=self.webcam_index_var, from_=0, to=5, width=4).pack(side="left", padx=4)
        self.btn_toggle_webcam = ttk.Button(roww, text=ui_tr(self.lang.get(), "open_cam"), command=self.toggle_webcam)
        self.btn_toggle_webcam.pack(side="left")

        self.ai_info = ttk.Label(card2, text="IA aguardando dados.", style="Body.TLabel", wraplength=640, justify="left")
        self.ai_info.pack(anchor="w", pady=(6, 2))
        self.learn_info = ttk.Label(card2, text="model: — | rows: 0 | training: idle", style="Body.TLabel", wraplength=640, justify="left")
        self.learn_info.pack(anchor="w")

    def _build_learning_tab_compact(self) -> None:
        box = ttk.Frame(self.tab_learning, style="Card.TFrame")
        box.pack(fill="both", expand=True)
        self.model_summary = ttk.Label(box, text="R², dataset, voice, music, frame and webcam will appear here.", justify="left", wraplength=700)
        self.model_summary.pack(anchor="w")
        self.ai_info_learning = ttk.Label(box, text="O modelo atual continua em execução enquanto um novo modelo treina em paralelo.", style="Body.TLabel", wraplength=700, justify="left")
        self.ai_info_learning.pack(anchor="w", pady=(8,0))

    def _build_log_tab_compact(self) -> None:
        self.log_text = tk.Text(self.tab_log, height=18, wrap="word", bg="#0f1720", fg="#dbeafe", insertbackground="#dbeafe")
        self.log_text.pack(fill="both", expand=True)

    def _build_help_tab_compact(self) -> None:
        self.help_label = ttk.Label(self.tab_help, text=ui_tr(self.lang.get(), "help_text"), justify="left", wraplength=720)
        self.help_label.pack(anchor="nw")

    def _show_robot_panel(self) -> None:
        robot = self.robot_var.get()
        if robot == "Manipulator":
            self.manip_frame.tkraise()
        elif robot == "Vehicle":
            self.vehicle_frame.tkraise()
        else:
            self.drone_frame.tkraise()

    def _apply_robot_defaults(self) -> None:
        super()._apply_robot_defaults()
        try:
            self._show_robot_panel()
        except Exception:
            pass

    def _apply_language(self) -> None:
        lang = self.lang.get()
        self.root.title(ui_tr(lang, "title"))
        # top bar
        self.btn_connect.configure(text=ui_tr(lang, "connect"))
