    def _add_slider_compact(self, parent, row: int, col: int, label: str, var, lo: float, hi: float, res: float) -> None:
        cell = ttk.Frame(parent, style="Card.TFrame")
        cell.grid(row=row, column=col, sticky="nsew", padx=3, pady=2)
        ttk.Label(cell, text=f"{label}  ({int(lo)}-{int(hi)})" if res >= 1 else label, style="Body.TLabel").pack(anchor="w")
        line = ttk.Frame(cell, style="Card.TFrame")
        line.pack(fill="x")
        group = self._manual_group_for_var(var)
        scale = tk.Scale(line, variable=var, from_=lo, to=hi, resolution=res, orient="horizontal", showvalue=False, command=(lambda _value, slider_var=var, manual_group=self._manual_group_for_var(var): self._on_manual_slider_input(slider_var, manual_group)), length=165, bg="#f7f8fa", highlightthickness=0)
        scale.pack(side="left", fill="x", expand=True)
        entry = ttk.Entry(line, textvariable=var, width=6)
        entry.pack(side="left", padx=(4, 0))
        entry.bind("<Return>", lambda e, slider_var=var, manual_group=group: self._on_manual_slider_input(slider_var, manual_group))
        entry.bind("<FocusOut>", lambda e, slider_var=var, manual_group=group: self._on_manual_slider_input(slider_var, manual_group))

