INTENT_LIBRARY_PATH = DATA_DIR / "synrov_base_intents.json"
USER_CONFIG_PATH = DATA_DIR / "synrov_user_config.json"


@dataclass
class BaseIntentProfile:
    name: str
    robot: str = "Any"
    phrases: List[str] = field(default_factory=list)
    action_type: str = "symbolic"  # symbolic | action
    payload: str = ""
    enabled: bool = True

    def to_dict(self) -> Dict[str, Any]:
        return {
            "name": self.name,
            "robot": self.robot,
            "phrases": list(self.phrases),
            "action_type": self.action_type,
            "payload": self.payload,
            "enabled": bool(self.enabled),
        }

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> "BaseIntentProfile":
        phrases = data.get("phrases", [])
        if isinstance(phrases, str):
            phrases = [p.strip() for p in phrases.replace("\n", ",").split(",") if p.strip()]
        return cls(
            name=str(data.get("name", "")).strip(),
            robot=str(data.get("robot", "Any") or "Any"),
            phrases=[str(p).strip() for p in phrases if str(p).strip()],
            action_type=str(data.get("action_type", "symbolic") or "symbolic"),
            payload=str(data.get("payload", "") or "").strip(),
            enabled=bool(data.get("enabled", True)),
        )


class IntentLibrary:
    def __init__(self, path: Path) -> None:
        self.path = Path(path)
        self._profiles: List[BaseIntentProfile] = []
        self.load()

    @property
    def profiles(self) -> List[BaseIntentProfile]:
        return list(self._profiles)

    def load(self) -> None:
        self._profiles = []
        if not self.path.exists():
            return
        try:
            raw = json.loads(self.path.read_text(encoding="utf-8"))
            if isinstance(raw, list):
                self._profiles = [BaseIntentProfile.from_dict(item) for item in raw if isinstance(item, dict)]
        except Exception:
            self._profiles = []

    def save(self) -> None:
        self.path.parent.mkdir(parents=True, exist_ok=True)
        payload = [p.to_dict() for p in self._profiles]
        self.path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")

    def upsert(self, profile: BaseIntentProfile) -> None:
        if not profile.name:
            raise ValueError("Nome da intenção é obrigatório")
        if not profile.phrases:
            raise ValueError("Informe pelo menos uma frase gatilho")
        if not profile.payload:
            raise ValueError("Informe a ação da intenção")
        replaced = False
        for i, current in enumerate(self._profiles):
            if current.name.lower() == profile.name.lower():
                self._profiles[i] = profile
                replaced = True
                break
        if not replaced:
            self._profiles.append(profile)
        self._profiles.sort(key=lambda x: x.name.lower())
        self.save()

    def delete(self, name: str) -> None:
        self._profiles = [p for p in self._profiles if p.name.lower() != str(name or "").lower()]
        self.save()

    def get(self, name: str) -> Optional[BaseIntentProfile]:
        key = str(name or "").strip().lower()
        for profile in self._profiles:
            if profile.name.lower() == key:
                return profile
        return None

    def match(self, text: str, robot: str) -> Optional[BaseIntentProfile]:
        norm = normalize_text(text)
        if not norm:
            return None
        scored: List[Tuple[int, BaseIntentProfile]] = []
        for profile in self._profiles:
            if not profile.enabled:
                continue
            if profile.robot not in {"Any", robot}:
                continue
            best = 0
            for phrase in profile.phrases:
                phrase_norm = normalize_text(phrase)
                if not phrase_norm:
                    continue
                if phrase_norm == norm:
                    best = max(best, len(phrase_norm) + 1000)
                elif phrase_norm in norm:
                    best = max(best, len(phrase_norm))
            if best > 0:
                scored.append((best, profile))
        if not scored:
            return None
        scored.sort(key=lambda item: item[0], reverse=True)
        return scored[0][1]


class IntentAwareVoiceParser(RichVoiceParser):
    def __init__(self, library: IntentLibrary) -> None:
        super().__init__()
        self.library = library

    def parse(self, text: str, robot: str) -> Tuple[str, float]:
        matched = self.library.match(text, robot)
        if matched is not None:
            if matched.action_type == "action":
                return f"action::{matched.payload}", 1.0
            return str(matched.payload or "none"), 1.0
        return super().parse(text, robot)


class VisualStatusTile(tk.Frame):
    COLORS = {
        "idle": ("#334155", "#e2e8f0", "#cbd5e1"),
        "ok": ("#166534", "#dcfce7", "#86efac"),
        "warn": ("#9a3412", "#ffedd5", "#fdba74"),
        "danger": ("#991b1b", "#fee2e2", "#fca5a5"),
        "info": ("#1d4ed8", "#dbeafe", "#93c5fd"),
        "active": ("#5b21b6", "#ede9fe", "#c4b5fd"),
    }

    def __init__(self, parent, title: str):
        super().__init__(parent, bg="#e2e8f0", bd=0, highlightthickness=1, highlightbackground="#cbd5e1", width=160)
        self.pack_propagate(False)
        self.title_label = tk.Label(self, text=title, anchor="w", font=("Segoe UI", 8, "bold"), bg="#e2e8f0", fg="#334155", width=18)
        self.title_label.pack(fill="x", padx=8, pady=(6, 0))
        self.state_label = tk.Label(self, text="—", anchor="w", font=("Segoe UI", 11, "bold"), bg="#e2e8f0", fg="#334155", width=18)
        self.state_label.pack(fill="x", padx=8, pady=(2, 0))
        self.detail_label = tk.Label(self, text="", anchor="w", justify="left", font=("Segoe UI", 7), bg="#e2e8f0", fg="#475569", wraplength=140)
        self.detail_label.pack(fill="x", padx=8, pady=(0, 6))

    def set_status(self, state_text: str, detail_text: str = "", tone: str = "idle") -> None:
        fg, bg, border = self.COLORS.get(tone, self.COLORS["idle"])
        self.configure(bg=bg, highlightbackground=border)
        self.title_label.configure(bg=bg, fg="#334155")
        self.state_label.configure(text=state_text, bg=bg, fg=fg)
        self.detail_label.configure(text=detail_text, bg=bg, fg="#475569")


