def command_center_tr(lang: str, key: str) -> str:
    bundle = COMMAND_CENTER_TR.get(lang, COMMAND_CENTER_TR["en"])
    return bundle.get(key, COMMAND_CENTER_TR["en"].get(key, key))


class SynROVPolishedCommandCenter(SynROVThreadedCommandCenter):
    def __init__(self, root: tk.Tk) -> None:
        self._guided_syncing = False
        self._last_auto_stage_applied = None
        self._config_syncing = False
        self._config_save_job = None
        self._config_vars_traced = False
        super().__init__(root)
        self._install_language_selector()
        self._prioritize_guided_learning_tab()
        self._install_learning_explainer_cards()
        self._open_guided_learning_on_startup()
        self._load_user_config()
        self._register_user_config_hooks()
        try:
            self.btn_mic.pack_forget()
        except Exception:
            pass
        self._apply_language()
        self.root.protocol("WM_DELETE_WINDOW", self._on_close)

    def _install_language_selector(self) -> None:
        if hasattr(self, "lang_combo_cc"):
            return
        self.lbl_language = ttk.Label(self.topbar, text=command_center_tr(self.lang.get(), "language") + ":")
        self.lbl_language.pack(side="left", padx=(10, 3), before=self.chk_ai)
        self.lang_combo_cc = ttk.Combobox(self.topbar, state="readonly", width=5, values=["en", "pt"], textvariable=self.lang)
        self.lang_combo_cc.pack(side="left", before=self.chk_ai)
        self.lang_combo_cc.bind("<<ComboboxSelected>>", lambda e: self._apply_language())

    def _install_learning_explainer_cards(self) -> None:
        # Cards are now built directly in _build_learning_tab_new() with proper
        # language support. This method is kept as a no-op to avoid breaking
        # subclasses that call super()._install_learning_explainer_cards().
        pass

    def _config_var_specs(self) -> List[Tuple[tk.Variable, str, str]]:
        return [
            (self.lang, "lang", "str"),
            (self.uri_var, "uri", "str"),
            (self.robot_var, "robot", "str"),
            (self.dataset_var, "dataset_path", "str"),
            (self.model_var, "model_path", "str"),
            (self.target_color_var, "target_color", "str"),
            (self.webcam_index_var, "webcam_index", "int"),
            (self.retrain_every_var, "retrain_every", "int"),
            (self.min_train_rows_var, "min_train_rows", "int"),
            (self.infer_period_ms, "infer_period_ms", "int"),
            (self.shadow_mode_var, "shadow_mode", "bool"),
            (self.spontaneity_var, "spontaneity", "bool"),
            (self.min_confidence_var, "min_confidence", "float"),
            (self.spontaneity_strength_var, "spontaneity_strength", "float"),
            (self.voice_hold_var, "voice_hold", "float"),
            (self.ai_gain_var, "ai_gain", "float"),
            (self.music_gain_var, "music_gain", "float"),
            (self.object_gain_var, "object_gain", "float"),
            (self.auto_collect_var, "auto_collect", "bool"),
            (self.auto_retrain_var, "auto_retrain", "bool"),
            (self.ai_enabled_var, "ai_enabled", "bool"),
            (self.direct_voice_var, "direct_voice", "bool"),
            (self.music_follow_var, "music_follow", "bool"),
            (self.object_follow_var, "object_follow", "bool"),
            (self.model_follow_var, "model_follow", "bool"),
            (self.safe_auto_var, "safe_auto", "bool"),
            (self.intent_enabled_var, "intent_enabled", "bool"),
            (self.learning_stage_var, "learning_stage", "int"),
        ]

    def _collect_user_config(self) -> Dict[str, Any]:
        return {
            "schema": 1,
            "lang": self.lang.get(),
            "uri": self.uri_var.get().strip(),
            "robot": self.robot_var.get().strip(),
            "dataset_path": self.dataset_var.get().strip(),
            "model_path": self.model_var.get().strip(),
            "target_color": self.target_color_var.get().strip(),
            "webcam_index": safe_int(self.webcam_index_var.get()),
            "retrain_every": safe_int(self.retrain_every_var.get()),
            "min_train_rows": safe_int(self.min_train_rows_var.get()),
            "infer_period_ms": safe_int(clamp_infer_period_ms(self.infer_period_ms.get(), 50)),
            "shadow_mode": bool(self.shadow_mode_var.get()),
            "spontaneity": bool(self.spontaneity_var.get()),
            "min_confidence": safe_float(self.min_confidence_var.get()),
            "spontaneity_strength": safe_float(self.spontaneity_strength_var.get()),
            "voice_hold": safe_float(self.voice_hold_var.get()),
            "ai_gain": safe_float(self.ai_gain_var.get()),
            "music_gain": safe_float(self.music_gain_var.get()),
            "object_gain": safe_float(self.object_gain_var.get()),
            "auto_collect": bool(self.auto_collect_var.get()),
            "auto_retrain": bool(self.auto_retrain_var.get()),
            "ai_enabled": bool(self.ai_enabled_var.get()),
            "direct_voice": bool(self.direct_voice_var.get()),
            "music_follow": bool(self.music_follow_var.get()),
            "object_follow": bool(self.object_follow_var.get()),
            "model_follow": bool(self.model_follow_var.get()),
            "safe_auto": bool(self.safe_auto_var.get()),
            "intent_enabled": bool(self.intent_enabled_var.get()),
            "learning_stage": safe_int(self.learning_stage_var.get()),
        }

    def _save_user_config_now(self) -> None:
        try:
            USER_CONFIG_PATH.parent.mkdir(parents=True, exist_ok=True)
            USER_CONFIG_PATH.write_text(json.dumps(self._collect_user_config(), ensure_ascii=False, indent=2), encoding="utf-8")
        except Exception as exc:
            try:
                self.log(f"[config] save error: {exc}")
            except Exception:
                pass

    def _schedule_user_config_save(self) -> None:
        if getattr(self, "_config_syncing", False):
            return
        try:
            if self._config_save_job is not None:
                self.root.after_cancel(self._config_save_job)
        except Exception:
            pass
        self._config_save_job = self.root.after(250, self._save_user_config_now)

    def _register_user_config_hooks(self) -> None:
        if getattr(self, "_config_vars_traced", False):
            return
        for var, _, _ in self._config_var_specs():
            try:
                var.trace_add("write", lambda *args: self._schedule_user_config_save())
            except Exception:
                pass
        self._config_vars_traced = True

    def _apply_loaded_value(self, var: tk.Variable, value: Any, kind: str) -> None:
        if value is None:
            return
        try:
            if kind == "bool":
                var.set(bool(value))
            elif kind == "int":
                var.set(safe_int(value))
            elif kind == "float":
                var.set(safe_float(value))
            else:
                var.set(str(value))
        except Exception:
            pass

    def _load_user_config(self) -> None:
        self._config_syncing = True
        try:
            data: Dict[str, Any] = {}
            if USER_CONFIG_PATH.exists():
                try:
                    raw = json.loads(USER_CONFIG_PATH.read_text(encoding="utf-8"))
                    if isinstance(raw, dict):
                        data = raw
                except Exception:
                    data = {}
            if not data:
                self.lang.set("en")
            for var, key, kind in self._config_var_specs():
                if key in data:
                    self._apply_loaded_value(var, data.get(key), kind)
            if self.lang.get() not in {"en", "pt"}:
                self.lang.set("en")
            if self.robot_var.get() not in {"Manipulator", "Vehicle", "Drone"}:
                self.robot_var.set("Manipulator")
            # Normalize to English canonical (handles both PT and EN saved values)
            self.target_color_var.set(_color_canonical(self.target_color_var.get()))
            self._apply_robot_defaults()
            if bool(self.auto_collect_var.get()):
                self.collector.start()
            else:
                self.collector.stop()
            self._apply_language()
        finally:
            self._config_syncing = False
        self._save_user_config_now()

    def _on_close(self) -> None:
        try:
            self._save_user_config_now()
        finally:
            try:
                self.preview_worker.stop()
            except Exception:
                pass
            try:
                self.ai_worker.stop()
            except Exception:
                pass
            try:
                self.bridge.disconnect()
            except Exception:
                pass
            try:
                self.voice_engine.stop()
            except Exception:
                pass
            try:
                self.webcam.stop()
            except Exception:
                pass
            self.root.destroy()

    def _prioritize_guided_learning_tab(self) -> None:
        # Put learning first — matches _sistema_v1_order_tabs priority.
        ordered = [self.tab_learning, self.tab_operation, self.tab_intents, self.tab_guide, self.tab_log]
        for index, child in enumerate(ordered):
            try:
                self.notebook.insert(index, child)
            except Exception:
                pass
        try:
            self.notebook.select(self.tab_learning)
        except Exception:
            pass

    def _guided_learning_steps(self) -> List[Dict[str, str]]:
        tr = lambda key: command_center_tr(self.lang.get(), key)
        return [
            {"title": self._tr("stage_prepare_title"), "desc": self._tr("stage_prepare_desc")},
            {"title": self._tr("stage_collect_title"), "desc": self._tr("stage_collect_desc")},
            {"title": self._tr("stage_voice_title"), "desc": self._tr("stage_voice_desc")},
            {"title": self._tr("stage_vision_title"), "desc": self._tr("stage_vision_desc")},
            {"title": self._tr("stage_train_title"), "desc": self._tr("stage_train_desc")},
            {"title": self._tr("stage_auto_title"), "desc": self._tr("stage_auto_desc")},
        ]

    def _guided_learning_labels(self) -> List[str]:
        return [
            command_center_tr(self.lang.get(), "check_base"),
            command_center_tr(self.lang.get(), "check_dataset"),
            command_center_tr(self.lang.get(), "check_voice"),
            command_center_tr(self.lang.get(), "check_vision"),
            command_center_tr(self.lang.get(), "check_model"),
            command_center_tr(self.lang.get(), "check_autonomy"),
        ]

    def _guided_text(self, pt: str, en: str) -> str:
        return en if self.lang.get() == "en" else pt

    def _guide_tab_text(self) -> str:
        return self._guided_text(
            """1. Abra o SynROV e confirme a porta WebSocket padrão (geralmente ws://127.0.0.1:9000/).

2. Escolha o mesmo robô aqui e no SynROV. Clique em Conectar.
   • Se a tile Telemetria ficar verde, os sensores estão chegando.
   • Se a tile Frame ficar verde, os frames estão chegando.

3. Teste primeiro o CONTROLE MANUAL.
   • Manipulator: base 0–359, demais membros 0–180.
   • Vehicle: teste MOVE.
   • Drone: teste FLY / TAKEOFF / LAND.

4. Ligue só os módulos que quiser.
   • Voz / texto: para frases e comandos base.
   • Música / ritmo: reage ao microfone quando não há uma voz recente bloqueando.
   • Visão / objeto: segue o alvo de cor do frame ou da webcam.
   • Modelo aprendido: usa o modelo treinado com o dataset.

5. Para aprender, ligue Coleta contínua e opere o robô.
   • O sistema grava telemetria, frame, áudio, texto/voz, visão e alvo de controle.
   • Quando houver linhas suficientes, clique em Treinar agora ou deixe o retreino automático ativo.

6. Intenções base.
   • Vá em 'Intenções base'.
   • Crie frases gatilho como 'abrir ferramenta' ou 'modo inspeção'.
   • Escolha 'symbolic' para usar intenções internas como arm_up, grip_open, vehicle_forward, drone_takeoff.
   • Escolha 'action' apenas para ações de alto nível como HOME, TAKEOFF ou LAND; movimento usa blocos atuais de controle.

7. Modo simulado.
   • O SynROV apenas mantém telemetria, frame e execução retornando ao painel.
   • Se 'Automação só em simulação' estiver ligado, voz/música/visão/modelo não comandam o robô fora da simulação.
   • O controle manual e a leitura de telemetria continuam visíveis no painel.

8. Se o frame parecer congelado.
   • Veja se a tile Frame está verde e se frames/s sobe.
   • Se telemetria sobe mas frame não, o SynROV não está enviando frame novo.
   • Se frame sobe e a imagem parece igual, a cena pode estar parada ou o preview ainda não mudou muito.""",
            """1. Open SynROV and confirm the default WebSocket port (usually ws://127.0.0.1:9000/).

2. Select the same robot here and in SynROV. Click Connect.
   • If the Telemetry tile turns green, sensor data is arriving.
   • If the Frame tile turns green, frames are arriving.

3. Test MANUAL CONTROL first.
   • Manipulator: base 0–359, other members 0–180.
   • Vehicle: test MOVE.
   • Drone: test FLY / TAKEOFF / LAND.

4. Enable only the modules you want.
   • Voice / text: for phrases and base commands.
   • Music / rhythm: reacts to the microphone when there is no recent voice command blocking it.
   • Vision / object: follows the target color in the frame or webcam.
   • Learned model: uses the model trained from the dataset.

5. To teach it, enable Continuous collection and operate the robot.
   • The system records telemetry, frame, audio, text/voice, vision and the control target.
   • When there are enough rows, click Train now or keep automatic retraining enabled.

6. Base intents.
   • Go to 'Base intents'.
   • Create trigger phrases such as 'open tool' or 'inspection mode'.
   • Choose 'symbolic' to use internal intents such as arm_up, grip_open, vehicle_forward or drone_takeoff.
   • Choose 'action' only for high-level actions such as HOME, TAKEOFF or LAND; motion uses current-schema control blocks.

7. Simulation mode.
   • SynROV only keeps telemetry, frame and execution flowing back to the panel.
   • If 'Block automatic commands' is enabled, voice/music/vision/model modules remain only in observation.
   • Manual control and telemetry reading remain visible in the panel.

8. If the frame looks frozen.
   • Check whether the Frame tile is green and whether frames/s increases.
   • If telemetry increases but the frame does not, SynROV is not sending a new frame.
   • If the frame increases but the image looks the same, the scene may simply be still or the preview has not changed enough yet."""
        )

