    def _open_guided_learning_on_startup(self) -> None:
        try:
            _, _, recommended = self._guided_learning_completion()
        except Exception:
            recommended = 0
        self.learning_stage_var.set(recommended)
        try:
            self._apply_learning_stage_settings(recommended, navigate=False)
            self._last_auto_stage_applied = recommended
        except Exception:
            pass
        def _focus_learning():
            try:
                self.notebook.select(self.tab_learning)
            except Exception:
                pass
        self.root.after(0, _focus_learning)
        self.root.after(120, _focus_learning)
        self.root.after(450, _focus_learning)

    def _refresh_guided_learning(self, force: bool = False) -> None:
        if not hasattr(self, "learning_stage_progress"):
            return
        steps = self._guided_learning_steps()
        checks, completed, recommended = self._guided_learning_completion()
        idx = max(0, min(len(steps) - 1, int(self.learning_stage_var.get())))
        self.learning_stage_var.set(idx)
        step = steps[idx]
        self.learning_stage_title_var.set(command_center_tr(self.lang.get(), "stage").format(current=idx + 1, total=len(steps), title=step["title"]))
        self.learning_stage_desc_var.set(step["desc"])
        self.learning_stage_progress.configure(value=completed, maximum=len(steps))
        self.learning_stage_summary_var.set(
            command_center_tr(self.lang.get(), "guided_summary").format(
                completed=completed,
                total=len(steps),
                recommended=recommended + 1,
                title=steps[recommended]["title"],
            )
        )
        labels = self._guided_learning_labels()
        self.learning_stage_checklist_var.set("\n".join(f"{'✓' if checks[i] else '•'} {labels[i]}" for i in range(len(labels))))

        done_items = [labels[i] for i, flag in enumerate(checks) if flag]
        stage_missing = [labels[i] for i in range(idx + 1) if not checks[i]]
        overall_missing = [labels[i] for i, flag in enumerate(checks) if not flag]

        if done_items:
            self.learning_stage_done_var.set("\n".join(f"✓ {item}" for item in done_items))
        else:
            self.learning_stage_done_var.set(self._guided_text("Nenhum check concluído automaticamente ainda.", "No checks have been completed automatically yet."))

        action_lines = self._guided_stage_actions(idx)
        if stage_missing:
            self.learning_stage_status_var.set(
                self._guided_text(
                    f"Etapa atual ainda não concluída. O guia abaixo usa exatamente os nomes dos controles reais da interface.",
                    f"Current step is not complete yet. The guide below uses the exact names of the real UI controls.",
                )
            )
            details = [f"• {item}" for item in stage_missing]
            if action_lines:
                details.append("")
                details.extend(f"→ {item}" for item in action_lines)
            self.learning_stage_missing_var.set("\n".join(details))
        elif overall_missing:
            self.learning_stage_status_var.set(
                self._guided_text(
                    f"Etapa atual concluída. O próximo passo recomendado é a etapa {recommended + 1} — {steps[recommended]['title']}. As ações abaixo usam os nomes reais dos controles.",
                    f"Current step is complete. The next recommended step is step {recommended + 1} — {steps[recommended]['title']}. The actions below use the real control names.",
                )
            )
            next_actions = self._guided_stage_actions(recommended)
            details = [f"• {item}" for item in overall_missing[:2]]
            if next_actions:
                details.append("")
                details.extend(f"→ {item}" for item in next_actions)
            self.learning_stage_missing_var.set("\n".join(details))
        else:
            self.learning_stage_status_var.set(self._guided_text("Todas as etapas do fluxo guiado já foram concluídas.", "All guided flow steps have already been completed."))
            self.learning_stage_missing_var.set(self._guided_text("Nada pendente no fluxo guiado.", "Nothing is pending in the guided flow."))
        try:
            self.btn_prev_stage.configure(state="normal" if idx > 0 else "disabled")
            self.btn_next_stage.configure(state="normal" if idx < len(steps) - 1 else "disabled")
        except Exception:
            pass

    def _auto_apply_recommended_learning_stage(self, force: bool = False, select_learning: bool = False) -> None:
        if self._guided_syncing:
            return
        try:
            _, _, recommended = self._guided_learning_completion()
        except Exception:
            return
        current = int(self.learning_stage_var.get()) if hasattr(self, "learning_stage_var") else 0
        if not force and recommended == current and self._last_auto_stage_applied == recommended:
            if select_learning:
                try:
                    self.notebook.select(self.tab_learning)
                except Exception:
                    pass
            return
        self._guided_syncing = True
        try:
            self.learning_stage_var.set(recommended)
            self._apply_learning_stage_settings(recommended, navigate=False)
            self._last_auto_stage_applied = recommended
            self.log(command_center_tr(self.lang.get(), "auto_guided_log").format(stage=recommended + 1, title=self._guided_learning_steps()[recommended]["title"]))
            if select_learning:
                try:
                    self.notebook.select(self.tab_learning)
                except Exception:
                    pass
        finally:
            self._guided_syncing = False

    def _clear_connection_state(self) -> None:
        state = self.bridge.state
        state.connected = False
        state.status = "disconnected"
        state.control_owner = "none"
        state.telemetry_source = "local"
        state.communication_protocol = "ascii"
        state.simulation = None
        state.connection_ts = 0.0
        state.telemetry_bootstrap = False
        state.leap_enabled = False
        state.leap_available = False
        state.joystick_enabled = False
        state.joystick_connected = False
        state.sensors.clear()
        state.gps.clear()
        state.control.clear()
        state.snapshot.clear()
        state.servos.clear()
        state.last_frame_pil = None
        state.last_frame_ts = 0.0
        state.last_msg_ts = 0.0
        state.frame_counter = 0
        state.telemetry_counter = 0
        state.last_runtime = ""
        if hasattr(state, "neutral_members"):
            state.neutral_members = [False] * len(MANIP_KEYS)
        self.last_command_ts = 0.0
        self.last_command_source = "none"
        self.last_command_target = None
        self._frame_hz = 0.0
        self._telem_hz = 0.0
        self._cached_synrov_feat = list(self._zero_image_feat)
        self._cached_webcam_feat = list(self._zero_image_feat)
        self._cached_vision = VisionInfo()
        self.last_vision = VisionInfo()
        self._last_synrov_feat_key = -1
        self._last_vision_key = None
        self._preview_rendered_keys = {"synrov": None, "webcam": None}
        self._preview_requested_keys = {"synrov": None, "webcam": None}
        self._preview_frame_key = None
        self.preview_photo = None
        try:
            self.preview_panel.configure(image="", text=command_center_tr(self.lang.get(), "preview_wait"))
        except Exception:
            pass
        try:
            self.preview_info_label.configure(text=command_center_tr(self.lang.get(), "no_new_frame"))
        except Exception:
            pass

    def _sync_selected_robot_to_synrov(self, force: bool = False) -> None:
        """Requests a fresh state snapshot without forcing SynROV robot mode.

        The main SynROV UI is the source of truth for the selected robot while
        connected. The Python panel mirrors that selection instead of fighting it.
        """
        try:
            bridge = self.bridge
            state = bridge.state
        except Exception:
            return
        if bridge is None or not getattr(state, "connected", False):
            return
        try:
            bridge.send_json({"sync": True})
        except Exception as exc:
            try:
                self.log(self._guided_text(f"[sync] falha ao solicitar estado do SynROV: {exc}", f"[sync] failed to request SynROV state: {exc}"))
            except Exception:
                pass

    def connect(self) -> None:
        self._clear_connection_state()
        super().connect()   # dispara thread WebSocket — não bloqueia
        # Adiar todos os refreshes para depois do retorno do clique
        try:
            self.root.after(50,  lambda: self._refresh_guided_learning(force=True))
            self.root.after(280, lambda: self._sync_selected_robot_to_synrov(force=False))
            self.root.after(720, lambda: self._sync_selected_robot_to_synrov(force=False))
        except Exception:
            pass

    def disconnect(self) -> None:
        try:
            self.bridge.disconnect()
        finally:
            self._clear_connection_state()
            self.log(command_center_tr(self.lang.get(), "disconnected_log"))
            try:
                self.root.after(0, lambda: self._refresh_guided_learning(force=True))
                self.root.after(0, self._apply_language)
            except Exception:
                pass

    def _apply_robot_defaults(self) -> None:
        super()._apply_robot_defaults()
        self._refresh_guided_learning(force=True)
        self._sync_selected_robot_to_synrov(force=False)

    def _set_intent_help(self) -> None:
        if not hasattr(self, "intent_help_label"):
            return
        if self.intent_action_type_var.get() == "action":
            text = (
                "Action block: send only a high-level action such as HOME, TAKEOFF or LAND"
                if self.lang.get() == "en"
                else "Bloco de ação: envia apenas ação de alto nível como HOME, TAKEOFF ou LAND"
            )
        else:
            text = (
                "Symbolic action: use an internal intent such as arm_up, grip_open, vehicle_forward or drone_takeoff."
                if self.lang.get() == "en"
                else "Ação simbólica: usa uma intenção interna como arm_up, grip_open, vehicle_forward ou drone_takeoff."
            )
        self.intent_help_label.configure(text=text)

    def _apply_language(self) -> None:
        lang = self.lang.get()
        tr = lambda key: command_center_tr(lang, key)
        _t = lambda pt, en: en if lang == "en" else pt
        self.root.title(self._tr("app_title"))
        if hasattr(self, "btn_connect"):
            self.btn_connect.configure(text=self._tr("connect"))
        if hasattr(self, "btn_disconnect"):
            self.btn_disconnect.configure(text=self._tr("disconnect"))
        if hasattr(self, "chk_ai"):
            self.chk_ai.configure(text=self._tr("autonomy"))
        if hasattr(self, "btn_mic"):
            self.btn_mic.configure(text=self._tr("stop_mic") if self.voice_engine.running else self._tr("start_mic"))
        if hasattr(self, "btn_voice_toggle"):
            self.btn_voice_toggle.configure(text=self._tr("stop_mic") if self.voice_engine.running else self._tr("start_mic"))
        if hasattr(self, "lbl_language"):
            self.lbl_language.configure(text=self._tr("language") + ":")
        # Sequential module checkboxes — numbered text stays consistent
        
        texts = getattr(self, '_operation_module_texts', lambda: {})() if hasattr(self, '_operation_module_texts') else {}
        def _chk(attr, key, pt_fallback, en_fallback):
            w = getattr(self, attr, None)
            if w is None: return
            try: w.configure(text=texts.get(key) or _t(pt_fallback, en_fallback))
            except Exception: pass
        _chk('chk_orchestrated_ui', 'orchestrated', '1 · IA orquestrada por robô', '1 · Orchestrated AI per robot')
