    def _synrov_image_eval_enabled(self) -> bool:
        try:
            robot = normalize_robot_name(self.robot_var.get(), "Manipulator")
            if robot == "Manipulator":
                return True
        except Exception:
            pass
        try:
            return super()._synrov_image_eval_enabled()
        except Exception:
            try:
                return bool(self.software_image_training_var.get())
            except Exception:
                return True

    def _object_action(self, vision: VisionInfo) -> bool:
        mission = getattr(self, "active_mission", None)
        if isinstance(mission, dict):
            try:
                ctx = self.voice_engine.context()
            except Exception:
                ctx = {}
            state = self.bridge.state
            try:
                telemetry_feat, synrov_feat, webcam_feat, audio_feat, current_vision = self._compute_cached_features(
                    state,
                    getattr(state, "last_frame_pil", None) if self._synrov_image_eval_enabled() else None,
                    getattr(self.webcam, "last_frame_pil", None) if hasattr(self, "webcam") else None,
                    time.time(),
                )
                return self._mission_step(telemetry_feat, synrov_feat, webcam_feat, audio_feat, current_vision, ctx) or True
            except Exception:
                return False
        return False

    def _music_action(self, audio_feat: List[float]) -> bool:
        if isinstance(getattr(self, "active_mission", None), dict):
            return False
        now = time.time()
        if now < safe_float(getattr(self, "_clean_controller_until", 0.0), 0.0) and getattr(self, "_clean_last_controller", "") not in {"audio", "music", "personality_audio", "personality_audio_startle"}:
            return False
        robot = normalize_robot_name(self.robot_var.get() if hasattr(self, "robot_var") else "Manipulator", "Manipulator")
        vals = (list(audio_feat or []) + [0.0] * 8)[:8]
        rms, peak, _zcr, _centroid, _low, _mid, _high, pulse = [safe_float(v, 0.0) for v in vals]
        active_startle = now < safe_float(getattr(self, "_audio_personality_startle_until", 0.0), 0.0)
        explicit_music = False
        try:
            ctx = self.voice_engine.context()
            explicit_music = str(ctx.get("intent", "none")) == "music_follow" and safe_float(ctx.get("text_age", 999.0)) < safe_float(self.voice_hold_var.get(), 8.0)
        except Exception:
            pass
        if robot == "Manipulator" and not (explicit_music or active_startle or peak > 0.045 or rms > 0.020 or pulse > 0.08):
            return False
        result = super()._music_action(audio_feat)
        if result:
            self._clean_last_controller = "audio"
            self._clean_controller_until = time.time() + 0.55
        return result

    def _ai_can_submit_model(self, vision: VisionInfo, voice_ctx: Dict[str, Any]) -> Tuple[bool, str]:
        mission = getattr(self, "active_mission", None)
        if isinstance(mission, dict):
            return False, "mission_priority"
        ok, reason = super()._ai_can_submit_model(vision, voice_ctx)
        if not ok:
            return ok, reason
        now = time.time()
        if now < safe_float(getattr(self, "_clean_controller_until", 0.0), 0.0):
            return False, "controller_lock"
        last_source = str(getattr(self, "last_command_source", "none") or "none")
        if last_source in {"manual", "voice", "music", "personality_audio", "personality_audio_startle", "vision", "mission"}:
            if now - safe_float(getattr(self, "last_command_ts", 0.0), 0.0) < 1.15:
                return False, "recent_controller"
        try:
            if safe_float(voice_ctx.get("text_age", 999.0), 999.0) < 1.5 and str(voice_ctx.get("intent", "none")) != "none":
                return False, "voice_priority"
        except Exception:
            pass
        return True, ""

    def _model_action(self, telemetry_feat: List[float], synrov_feat: List[float], webcam_feat: List[float], audio_feat: List[float], vision: VisionInfo, voice_ctx: Dict[str, Any]) -> bool:
        result = super()._model_action(telemetry_feat, synrov_feat, webcam_feat, audio_feat, vision, voice_ctx)
        if result:
            self._clean_last_controller = "model"
            self._clean_controller_until = time.time() + 0.45
        return result

    def _curiosity_tick_loop(self) -> None:
        try:
            if bool(getattr(self, "autonomous_learning_var", tk.BooleanVar(value=False)).get()):
                now = time.time()
                if now >= safe_float(getattr(self, "_clean_next_curiosity", 0.0), 0.0):
                    recent = now - safe_float(getattr(self, "last_command_ts", 0.0), 0.0) if getattr(self, "last_command_ts", 0.0) else 999.0
                    if recent > 3.0 and not isinstance(getattr(self, "active_mission", None), dict):
                        try:
                            if isinstance(getattr(self, "_curiosity_pending", None), dict):
                                self._curiosity_evaluate_pending()
                            else:
                                self._curiosity_submit_probe()
                        except Exception:
                            pass
                    self._clean_next_curiosity = now + 4.0
        finally:
            try:
                self.root.after(self.CURIOSITY_TICK_MS, self._curiosity_tick_loop)
            except Exception:
                pass

    def _mission_tick_loop(self) -> None:
        try:
            if isinstance(getattr(self, "active_mission", None), dict):
                now = time.time()
                if now >= safe_float(getattr(self, "_clean_next_mission", 0.0), 0.0):
                    self._clean_next_mission = now + max(0.28, self.MISSION_TICK_MS / 1000.0)
                    state = self.bridge.state
                    try:
                        voice_ctx = self.voice_engine.context()
                    except Exception:
                        voice_ctx = {}
                    try:
                        telemetry_feat, synrov_feat, webcam_feat, audio_feat, vision = self._compute_cached_features(
                            state,
                            getattr(state, "last_frame_pil", None) if self._synrov_image_eval_enabled() else None,
                            getattr(self.webcam, "last_frame_pil", None) if hasattr(self, "webcam") else None,
                            now,
                        )
                        if self._mission_step(telemetry_feat, synrov_feat, webcam_feat, audio_feat, vision, voice_ctx):
                            self._clean_last_controller = "mission"
                            self._clean_controller_until = time.time() + 0.70
                    except Exception:
                        pass
        finally:
            try:
                self.root.after(self.MISSION_TICK_MS, self._mission_tick_loop)
            except Exception:
                pass

    def _maybe_background_train(self) -> None:
        now = time.time()
        if now < safe_float(getattr(self, "_clean_next_train_check", 0.0), 0.0):
            return
        self._clean_next_train_check = now + self.TRAIN_CHECK_PERIOD_S
        return super()._maybe_background_train()

    def _ui_tick(self) -> None:
        try:
            self._ensure_digital_twin_learning_for_robot(force=False)
            self._clean_frontend_labels(force=False)
        except Exception:
            pass
        return super()._ui_tick()

    # ---- Final guided-learning and learning-protection cleanup ----------------
    def _inject_learning_guard_learning_guard_controls(self) -> None:
        """Create the learning-protection panel inside the Operation tab.

        Stored layers inserted this card in the guided-learning tab.  The user now
        sees and operates the protection controls next to the real operation,
        dataset and automation controls.
        """
        if getattr(self, "learning_guard_guard_card", None) is not None:
            return
        try:
            host = getattr(getattr(self, "tab_operation", None), "body", None)
            if host is None:
                host = getattr(getattr(self, "tab_learning", None), "body", None)
            if host is None:
                return
            self.learning_guard_guard_card = ttk.Frame(host, style="Card.TFrame", padding=8)
            # Put protection after the operation/config cards when possible.
            try:
                self.learning_guard_guard_card.pack(fill="x", pady=(0, 6), after=getattr(self, "operation_config_card"))
            except Exception:
                self.learning_guard_guard_card.pack(fill="x", pady=(0, 6))

            self.learning_guard_guard_title_label = ttk.Label(self.learning_guard_guard_card, text=self._learning_guard_text("guard_title"), style="Title.TLabel")
            self.learning_guard_guard_title_label.pack(anchor="w")
            self.learning_guard_guard_hint_label = ttk.Label(self.learning_guard_guard_card, text=self._learning_guard_text("guard_hint"), style="Body.TLabel", wraplength=760, justify="left", width=88)
            self.learning_guard_guard_hint_label.pack(anchor="w", pady=(4, 4))

            row1 = ttk.Frame(self.learning_guard_guard_card, style="Card.TFrame")
            row1.pack(fill="x", pady=2)
            self.chk_learning_guard_learning_guard = ttk.Checkbutton(row1, text=self._learning_guard_text("anti_drift"), variable=self.learning_guard_var, command=self._refresh_learning_guard_guard_status)
            self.chk_learning_guard_learning_guard.pack(side="left")
            self.chk_learning_guard_accept_gate = ttk.Checkbutton(row1, text=self._learning_guard_text("accept_gate"), variable=self.model_acceptance_gate_var, command=self._refresh_learning_guard_guard_status)
            self.chk_learning_guard_accept_gate.pack(side="left", padx=(10, 0))
            self.chk_learning_guard_auto_data = ttk.Checkbutton(row1, text=self._learning_guard_text("use_auto_data"), variable=self.autonomous_training_enabled_var, command=self._refresh_learning_guard_guard_status)
            self.chk_learning_guard_auto_data.pack(side="left", padx=(10, 0))

            row2 = ttk.Frame(self.learning_guard_guard_card, style="Card.TFrame")
            row2.pack(fill="x", pady=2)
            self.lbl_learning_guard_auto_limit = ttk.Label(row2, text=self._learning_guard_text("auto_limit"))
            self.lbl_learning_guard_auto_limit.pack(side="left")
            self.spin_learning_guard_auto_limit = ttk.Spinbox(row2, from_=0.0, to=0.45, increment=0.02, width=6, textvariable=self.autonomous_training_share_var, command=self._refresh_learning_guard_guard_status)
            self.spin_learning_guard_auto_limit.pack(side="left", padx=(4, 0))
            self.btn_learning_guard_rollback = ttk.Button(row2, text=self._learning_guard_text("rollback"), command=self.restore_saved_model_learning_guard)
            self.btn_learning_guard_rollback.pack(side="left", padx=(10, 0))

            self.lbl_learning_guard_guard_status = ttk.Label(self.learning_guard_guard_card, textvariable=self.training_quality_status_var, style="Info.TLabel", wraplength=760, justify="left", width=88)
            self.lbl_learning_guard_guard_status.pack(anchor="w", pady=(4, 0))
            self._refresh_learning_guard_guard_status()
        except Exception as exc:
            try:
                self.log_i18n(f"[proteção] falha ao criar painel: {exc}", f"[guard] failed to create panel: {exc}")
            except Exception:
                pass

