    def _guided_learning_completion(self) -> Tuple[List[bool], int, int]:
        try:
            robot = normalize_robot_name(self.robot_var.get(), "Manipulator")
        except Exception:
            robot = "Manipulator"
        state = getattr(getattr(self, "bridge", None), "state", SynROVState())
        rows = self._get_dataset_count_cached(robot) if hasattr(self, "_get_dataset_count_cached") else load_count(Path(self.dataset_var.get()), robot)
        score = safe_float(getattr(self, "training_info", {}).get("score", 0.0))
        trained = bool(robot in getattr(self, "model_packages", {}) or score > 0.0)
        telem_ok = bool(getattr(state, "connected", False) and safe_float(getattr(self, "_telem_hz", 0.0), 0.0) > 0.2)
        inputs_ok = bool(
            getattr(self, "dataset_ram_buffer_var", tk.BooleanVar(value=True)).get()
            and getattr(self, "robot_specific_telemetry_var", tk.BooleanVar(value=True)).get()
            and (robot != "Manipulator" or getattr(self, "software_image_training_var", tk.BooleanVar(value=True)).get())
        )
        manual_ok = bool(rows >= max(8, min(safe_int(self.min_train_rows_var.get(), 8), 40)) or (hasattr(self, "_movement_successes") and self._movement_successes("manual") > 0))
        voice_ok = bool(
            getattr(getattr(self, "voice_engine", None), "last_text", "")
            or (hasattr(self, "_movement_successes") and self._movement_successes("voice") > 0)
            or (getattr(self, "intent_library", None) is not None and len(getattr(self.intent_library, "profiles", [])) > 0)
        )
        av_ok = bool(
            (getattr(self, "audio_personality_var", tk.BooleanVar(value=False)).get() if hasattr(self, "audio_personality_var") else False)
            or (getattr(self, "object_follow_var", tk.BooleanVar(value=False)).get() and self._frame_is_fresh(state, 2.0))
            or (hasattr(self, "_movement_successes") and (self._movement_successes("music") + self._movement_successes("vision")) > 0)
        )
        guard_ok = bool(getattr(self, "learning_guard_var", tk.BooleanVar(value=True)).get() and trained)
        shadow_ok = bool(
            getattr(self, "shadow_mode_var", tk.BooleanVar(value=False)).get()
            or safe_int(getattr(self, "_shadow_score_samples", 0), 0) >= 4
            or (trained and score >= 0.0)
        )
        autonomy_ok = bool(getattr(self, "ai_enabled_var", tk.BooleanVar(value=False)).get() and getattr(self, "model_follow_var", tk.BooleanVar(value=False)).get() and trained)
        checks = [telem_ok, inputs_ok, manual_ok, voice_ok, av_ok, guard_ok, shadow_ok, autonomy_ok]
        completed = sum(1 for flag in checks if flag)
        recommended = next((i for i, flag in enumerate(checks) if not flag), len(checks) - 1)
        return checks, completed, recommended

