    def _apply_learning_stage_settings(self, idx: int, navigate: bool = True) -> None:
        idx = max(0, min(len(self._guided_learning_steps()) - 1, int(idx)))
        try:
            self.learning_stage_var.set(idx)
        except Exception:
            pass
        # Baseline: training-ready and protected, with only the currently guided
        # module enabled aggressively.  This avoids mixed examples while keeping
        # the AI ready for high interaction.
        for name, value in [
            ("learning_guard_var", True),
            ("model_acceptance_gate_var", True),
            ("dataset_ram_buffer_var", True),
            ("robot_specific_telemetry_var", True),
            ("auto_collect_var", idx >= 2),
            ("auto_retrain_var", idx >= 5),
            ("ai_enabled_var", idx >= 3),
            ("direct_voice_var", idx in {3, 7}),
            ("music_follow_var", idx == 4),
            ("object_follow_var", idx == 4),
            ("model_follow_var", idx >= 7),
            ("shadow_mode_var", idx == 6),
            ("spontaneity_var", False),
            ("safe_auto_var", False),
        ]:
            var = getattr(self, name, None)
            try:
                if var is not None:
                    var.set(value)
            except Exception:
                pass
        if idx >= 1:
            try:
                self._ensure_digital_twin_learning_for_robot(force=True)
            except Exception:
                pass
        try:
            self._toggle_collect()
        except Exception:
            pass
        if navigate:
            try:
                self.notebook.select(self.tab_operation if idx in {0, 1, 2, 3, 4, 5, 7} else self.tab_learning)
            except Exception:
                pass
        self._refresh_guided_learning(force=True)
        self._clean_frontend_labels(force=True)

    def _refresh_guided_learning(self, force: bool = False) -> None:
        if not hasattr(self, "learning_stage_progress"):
            return
        now = time.time()
        if not force and now < safe_float(getattr(self, "_final_next_guided_refresh", 0.0), 0.0):
            return
        self._final_next_guided_refresh = now + 1.4
        steps = self._guided_learning_steps()
        checks, completed, recommended = self._guided_learning_completion()
        total = len(steps)
        idx = max(0, min(total - 1, safe_int(self.learning_stage_var.get(), 0)))
        try:
            self.learning_stage_var.set(idx)
        except Exception:
            pass
        step = steps[idx]
        title = self._ui_text("Etapa {}/{} — {}", "Step {}/{} — {}").format(idx + 1, total, step.get("title", ""))
        summary = self._ui_text(
            "Fluxo guiado: {}/{} concluídas | leitura sugerida agora: etapa {} — {}",
            "Guided flow: {}/{} complete | suggested reading now: step {} — {}",
        ).format(completed, total, recommended + 1, steps[recommended].get("title", ""))
        labels = self._guided_learning_labels()
        checklist = "\n".join(f"{'✓' if checks[i] else '•'} {labels[i]}" for i in range(min(total, len(checks), len(labels))))
        done = [labels[i] for i, ok in enumerate(checks[:len(labels)]) if ok]
        missing = self._guided_stage_actions(idx)
        if idx != recommended and recommended < total:
            missing = [self._ui_text("Leitura recomendada agora: volte para a etapa {}.", "Suggested reading now: go to step {}.").format(recommended + 1)] + self._guided_stage_actions(recommended)
        self.learning_stage_title_var.set(title)
        self.learning_stage_desc_var.set(step.get("desc", ""))
        self.learning_stage_summary_var.set(summary)
        self.learning_stage_checklist_var.set(checklist)
        self.learning_stage_status_var.set(self._ui_text(
            "Leia de cima para baixo. Ao clicar em Aplicar esta etapa, o painel ajusta os módulos necessários e mantém a proteção de aprendizado ativa.",
            "Read from top to bottom. When you click Apply this step, the panel adjusts the needed modules and keeps learning protection active.",
        ))
        self.learning_stage_done_var.set("\n".join(f"✓ {item}" for item in done) if done else self._ui_text("Nenhum item concluído automaticamente ainda.", "No item has been completed automatically yet."))
        self.learning_stage_missing_var.set("\n".join(f"• {item}" for item in missing) if missing else self._ui_text("Nada pendente nesta etapa.", "Nothing pending in this step."))
        try:
            self.learning_stage_progress.configure(value=completed, maximum=total)
            self.btn_prev_stage.configure(state="normal" if idx > 0 else "disabled")
            self.btn_next_stage.configure(state="normal" if idx < total - 1 else "disabled")
        except Exception:
            pass


    def _clean_frontend_labels(self, force: bool = False) -> None:
        now = time.time()
        if not force and now < safe_float(getattr(self, "_clean_next_text_refresh", 0.0), 0.0):
            return
