# Final voice backend: Google SpeechRecognition + language-safe UI texts
# -----------------------------------------------------------------------------
try:
    import speech_recognition as _synrov_sr  # type: ignore
    sr = _synrov_sr  # type: ignore
    _SR_IMPORT_ERROR = ""
except Exception as _synrov_google_import_exc:
    _synrov_sr = None  # type: ignore
    sr = None  # type: ignore
    _SR_IMPORT_ERROR = str(_synrov_google_import_exc)


def _synrov_lang_code_final(self) -> str:
    for attr in ("lang", "language_var", "ui_language_var"):
        try:
            var = getattr(self, attr, None)
            if hasattr(var, "get"):
                return str(var.get() or "pt").strip().lower()
            if isinstance(var, str):
                return var.strip().lower()
        except Exception:
            pass
    return "pt"


def _synrov_pair_final(self, pt: str, en: str) -> str:
    try:
        return self._ui_pair(pt, en)
    except Exception:
        return en if _synrov_lang_code_final(self).startswith("en") else pt


def _synrov_parse_device_index_final(device: Any) -> Optional[int]:
    if device in (None, "", "auto", "default"):
        return None
    try:
        if isinstance(device, int):
            return int(device)
        text = str(device).strip()
        if text.isdigit():
            return int(text)
        m = re.match(r"\s*(\d+)\s*(?:[·\-:)]|$)", text)
        if m:
            return int(m.group(1))
    except Exception:
        pass
    try:
        return _synrov_parse_audio_device_selection(device)  # type: ignore[name-defined]
    except Exception:
        return None


def _synrov_safe_audio_device_label(device: Any) -> str:
    # Fast, non-blocking label. Never enumerate devices here; UI calls this every tick.
    if device in (None, "", "auto", "default"):
        return "Auto / microfone padrão"
    try:
        idx = _synrov_parse_device_index_final(device)
        if idx is not None:
            return f"{idx}"
    except Exception:
        pass
    return str(device)


class GoogleVoiceAudioEngine:
    """Online Google speech recognition with local microphone meter.

    This replaces the previous Vosk backend. It does not require an offline model;
    it needs SpeechRecognition/PyAudio and internet access for Google's recognizer.
    """

    def __init__(self, parser: RichVoiceParser, robot_getter, language_getter=None) -> None:
        self.parser = parser
        self.robot_getter = robot_getter
        self.language_getter = language_getter or (lambda: "pt")
        self.running = False
        self.last_text = ""
        self.last_norm = ""
        self.last_intent = "none"
        self.last_conf = 0.0
        self.last_text_ts = 0.0
        self.audio_level = 0.0
        self.audio_peak = 0.0
        self.audio_meter = 0.0
        self.audio_features = [0.0] * len(AUDIO_KEYS)
        self.audio_ts = 0.0
        self.last_sr_error = ""
        self.status_message = ""
        self.audio_backend = "off"
        self.speech_backend = "google_idle"
        self.device = os.environ.get("SYNROV_VOICE_DEVICE", "") or None
        self.device_label = _synrov_safe_audio_device_label(self.device)
        self._stream = None
        self._audio_lock = threading.Lock()
        self._state_lock = threading.RLock()
        self._speech_thread: Optional[threading.Thread] = None
        self._audio_thread: Optional[threading.Thread] = None
        self._recognition_thread: Optional[threading.Thread] = None
        self._recognition_busy = False
        self._prev_rms = 0.0
        self._noise_floor = 0.0035
        self._partial_text = ""
        self._meter_proc = None

    def set_device(self, device: Any) -> None:
        self.device = device
        self.device_label = _synrov_safe_audio_device_label(device)

    def _recognition_languages(self) -> List[str]:
        try:
            lang = str(self.language_getter() or "").strip().lower()
        except Exception:
            lang = "pt"
        primary = "pt-BR" if lang.startswith("pt") else "en-US"
        fallback = "en-US" if primary == "pt-BR" else "pt-BR"
        return [primary, fallback]

    def start(self) -> bool:
        # This method must never block Tkinter. All audio, device opening and Google
        # network recognition are performed in daemon threads with short timeouts.
        if self.running:
            return True
        self.last_sr_error = ""
        self.status_message = ""
        self.audio_backend = "starting"
        self.speech_backend = "starting_google"
        self.device_label = _synrov_safe_audio_device_label(self.device)
        if _synrov_sr is None:
            self.audio_backend = "off"
            self.speech_backend = "missing_dependency"
            self.last_sr_error = (
                "SpeechRecognition/PyAudio ausente. Instale com: "
                "python -m pip install SpeechRecognition PyAudio. Detalhe: " + str(_SR_IMPORT_ERROR)
            )
            self.status_message = self.last_sr_error
            return False
        self.running = True
        # The audio meter always uses PyAudio in a dedicated thread.
        if self._audio_thread is None or not self._audio_thread.is_alive():
            self._audio_thread = threading.Thread(target=self._pyaudio_audio_loop, name="synrov-pyaudio-meter", daemon=True)
            self._audio_thread.start()
        self.audio_backend = "pyaudio_meter"
        if self._speech_thread is None or not self._speech_thread.is_alive():
            self._speech_thread = threading.Thread(target=self._speech_loop, name="synrov-google-speech", daemon=True)
            self._speech_thread.start()
        return True

    def stop(self) -> None:
        self.running = False
        # Stop the audio meter subprocess.
        try:
            if self._meter_proc is not None and self._meter_proc.poll() is None:
                self._meter_proc.terminate()
        except Exception:
            pass
        self._meter_proc = None
        # Stop the active audio stream when present.
        try:
            if self._stream is not None:
                try: self._stream.stop()
                except Exception: pass
                try: self._stream.close()
                except Exception: pass
        except Exception:
            pass
        self._stream = None
        # Reset the audio state.
        with self._audio_lock:
            self.audio_level   = 0.0
            self.audio_peak    = 0.0
            self.audio_meter   = 0.0
            self.audio_features = [0.0] * len(AUDIO_KEYS)
        self.speech_backend = "google_idle"
        self.audio_backend  = "off"
        self.status_message = "Microfone parado."


    def _pyaudio_audio_loop(self) -> None:
        """Monitor de nivel de audio via subprocesso Python isolado.

        PyAudio pode causar crash nativo no Windows (DLL/driver de audio).
        Rodando em subprocesso separado, um crash do driver nao derruba o app.
        O subprocesso envia JSON lines com r=rms, p=peak, u=pulse pelo stdout.
        """
        import subprocess as _sp, sys as _sys, json as _json, base64 as _b64

        _b64_script = ""
        _runner = (
            "import base64,types\n"
            "exec(compile(base64.b64decode('" + _b64_script + "').decode(),'<m>','exec'))\n"
        )

        proc = None
        try:
            proc = _sp.Popen(
                [_sys.executable, "-c", _runner],
                stdout=_sp.PIPE,
                stderr=_sp.PIPE,
                text=True,
                bufsize=1,
            )
            self._meter_proc = proc   # expoe para stop()
            # Aguarda confirmacao de startup ate 5 s
            _deadline = time.time() + 5.0
            _started  = False
            while time.time() < _deadline:
                if proc.poll() is not None:
                    _err = ""
                    try: _err = proc.stderr.read()[:300]
                    except Exception: pass
                    self.audio_backend  = "pyaudio_error"
                    self.last_sr_error  = "Monitor de audio falhou: " + _err
                    self.status_message = self.last_sr_error
                    return
                try:
                    line = proc.stdout.readline()
                    if line and line.strip():
                        _started = True
                        break
                except Exception:
                    pass
                time.sleep(0.05)

            if not _started:
                self.audio_backend  = "pyaudio_timeout"
                self.last_sr_error  = "Monitor de audio nao respondeu em 5s (driver travado?)."
                self.status_message = self.last_sr_error
                try: proc.terminate()
                except Exception: pass
                return

            self.audio_backend  = "pyaudio_subprocess"
            self.status_message = "Monitor de audio ativo (subprocesso isolado)."

            while self.running:
                if proc.poll() is not None:
                    self.audio_backend = "pyaudio_stopped"
                    break
                try:
                    line = proc.stdout.readline()
                    if not line:
                        time.sleep(0.03)
                        continue
                    line = line.strip()
                    if not line or line[0] != "{":
                        continue
                    d     = _json.loads(line)
                    rms   = float(d.get("r",  0.0))
                    peak  = float(d.get("p",  0.0))
                    pulse = float(d.get("u",  0.0))
                    nf = safe_float(self._noise_floor, 0.0035)
                    nf = (0.985*nf + 0.015*max(rms, 0.0001)) if rms <= nf*1.5 else (0.997*nf + 0.003*rms)
                    self._noise_floor = clamp(nf, 0.0004, 0.08)
                    visual = clamp(
                        (max(rms, peak*0.72) - self._noise_floor*0.8)
                        / max(0.012, 0.090 - self._noise_floor),
                        0.0, 1.0,
                    )
                    self.audio_meter = clamp(0.72*safe_float(self.audio_meter, 0.0) + 0.28*visual, 0.0, 1.0)
                    feats = [rms, peak, 0.0, 0.5, 0.33, 0.33, 0.33, pulse]
                    with self._audio_lock:
                        self.audio_features = feats
                        self.audio_level    = rms
                        self.audio_peak     = peak
                        self.audio_ts       = time.time()
                except Exception:
                    time.sleep(0.03)

        except Exception as exc:
            self.audio_backend  = "pyaudio_error"
            self.last_sr_error  = "Monitor de audio: " + str(exc)
            self.status_message = self.last_sr_error
        finally:
            if proc:
                try: proc.terminate()
                except Exception: pass


    def inject_text(self, text: str) -> None:
        text = str(text or "").strip()
        if not text:
            return
        robot = self.robot_getter()
        intent, conf = self.parser.parse(text, robot)
        self.last_text = text
        self.last_norm = normalize_text(text)
        self.last_intent = intent
        self.last_conf = conf
        self.last_text_ts = time.time()
        self._partial_text = ""


    def _audio_loop(self) -> None:
        """Não utilizado — captura via _pyaudio_audio_loop."""
        pass

    def _speech_loop(self) -> None:
        if _synrov_sr is None:
            return
        recognizer = _synrov_sr.Recognizer()
        try:
            recognizer.operation_timeout = 2.5
            recognizer.pause_threshold = 0.65
            recognizer.dynamic_energy_threshold = True
        except Exception:
            pass
        selected_idx = _synrov_parse_device_index_final(self.device)
        candidates: List[Optional[int]] = []
        if selected_idx is not None:
            candidates.append(selected_idx)
        candidates.append(None)
        last_open_error = ""
        for mic_index in candidates:
            if not self.running:
                return
            try:
                self.device_label = _synrov_safe_audio_device_label(mic_index)
                with _synrov_sr.Microphone(device_index=mic_index) as source:
                    self.speech_backend = "google_microphone_ready"
                    self.status_message = f"Google Speech pronto em {self.device_label}"
                    try:
                        recognizer.adjust_for_ambient_noise(source, duration=0.10)
                    except Exception:
                        pass
                    while self.running:
                        try:
                            self.speech_backend = "google_listening"
                            audio = recognizer.listen(source, timeout=0.75, phrase_time_limit=2.6)
                        except _synrov_sr.WaitTimeoutError:
                            continue
                        except Exception as exc:
                            self.last_sr_error = f"Falha ao escutar microfone: {exc}"
                            time.sleep(0.25)
                            continue
                        self._recognize_google_async(recognizer, audio)
                    return
            except Exception as exc:
                last_open_error = str(exc)
                continue
        self.speech_backend = "microphone_error"
        self.last_sr_error = (
            "Falha ao conectar no microfone. Verifique permissões do Windows, se outro programa está usando o microfone "
            f"e se o PyAudio está instalado. Detalhe: {last_open_error}"
        )
        self.status_message = self.last_sr_error
        self.running = False

    def _recognize_google_async(self, recognizer: Any, audio: Any) -> None:
        # Keep Google/network recognition away from the capture loop and the UI.
        if self._recognition_busy:
            return
        self._recognition_busy = True
        def worker() -> None:
            text = ""
            last_error = ""
            try:
                for language in self._recognition_languages():
                    if not self.running:
                        return
                    try:
                        self.speech_backend = f"google_recognizing_{language}"
                        text = recognizer.recognize_google(audio, language=language)
                        if text:
                            break
                    except _synrov_sr.UnknownValueError:
                        last_error = "não entendi o áudio"
                        text = ""
                    except _synrov_sr.RequestError as exc:
                        last_error = f"Google Speech não respondeu ou sem internet: {exc}"
                        text = ""
                        break
                    except Exception as exc:
                        last_error = f"Falha no reconhecimento Google: {exc}"
                        text = ""
                if text:
                    self.inject_text(text)
                    self.speech_backend = "google_recognized"
                    self.status_message = f"Reconhecido: {text}"
                    self.last_sr_error = ""
                elif last_error:
                    self.last_sr_error = last_error
                    self.status_message = last_error
            finally:
                self._recognition_busy = False
        self._recognition_thread = threading.Thread(target=worker, name="synrov-google-recognizer", daemon=True)
        self._recognition_thread.start()

    def context(self) -> Dict[str, Any]:
        with self._audio_lock:
            feats = list(self.audio_features)
            lvl = self.audio_level
            peak = self.audio_peak
            ats = self.audio_ts
        diag = self.status_message or self.last_sr_error
        return {
            "raw": self.last_text,
            "text": self.last_text,
            "norm": self.last_norm,
            "intent": self.last_intent,
            "conf": self.last_conf,
            "text_age": time.time() - self.last_text_ts if self.last_text_ts else 999.0,
            "audio_features": feats,
            "audio_level": lvl,
            "audio_peak": peak,
            "audio_meter": clamp(safe_float(self.audio_meter, 0.0), 0.0, 1.0),
            "audio_age": time.time() - ats if ats else 999.0,
            "error": self.last_sr_error,
            "audio_backend": self.audio_backend,
            "speech_backend": self.speech_backend,
            "diagnostics": diag,
            "partial": self._partial_text,
            "offline": False,
            "model_path": "",
            "device_label": getattr(self, "device_label", _synrov_safe_audio_device_label(self.device)),
        }


VoiceAudioEngine = GoogleVoiceAudioEngine
