def _synrov_find_children_by_text(root: Any, texts: set[str]) -> List[Any]:
    found: List[Any] = []
    def walk(widget: Any) -> None:
        try:
            if str(widget.cget("text")) in texts:
                found.append(widget)
        except Exception:
            pass
        try:
            for child in widget.winfo_children():
                walk(child)
        except Exception:
            pass
    try:
        walk(root)
    except Exception:
        pass
    return found


def _synrov_apply_dynamic_language_google(self) -> None:
    pt = not _synrov_lang_code_final(self).startswith("en")
    root = getattr(self, "root", None)
    try:
        if root is not None:
            for w in _synrov_find_children_by_text(root, {"Microfone:", "Microphone:"}):
                w.configure(text=("Microfone:" if pt else "Microphone:"))
            for w in _synrov_find_children_by_text(root, {"Atualizar", "Refresh"}):
                # Avoid changing unrelated refreshes badly; button text is safe for all refresh buttons.
                w.configure(text=("Atualizar" if pt else "Refresh"))
            for w in _synrov_find_children_by_text(root, {"Reconhecimento:", "Recognition:"}):
                w.configure(text=("Reconhecimento:" if pt else "Recognition:"))
            for w in _synrov_find_children_by_text(root, {"Telemetria da IA:", "AI telemetry:"}):
                w.configure(text=("Telemetria da IA:" if pt else "AI telemetry:"))
    except Exception:
        pass

    try:
        if getattr(self, "btn_refresh_audio_devices", None) is not None:
            self.btn_refresh_audio_devices.configure(text=("Atualizar" if pt else "Refresh"))
    except Exception:
        pass
    try:
        if getattr(self, "operation_mode_status_label", None) is not None:
            self.operation_mode_status_label.configure(text=_synrov_pair_final(
                self,
                "Modo orquestrado ativo por padrão. Use a trava abaixo para impedir comandos automáticos.",
                "Orchestrated mode is active by default. Use the lock below to prevent automatic commands.",
            ))
    except Exception:
        pass
    try:
        if getattr(self, "operation_model_status_label", None) is not None:
            self.operation_model_status_label.configure(text=_synrov_pair_final(
                self,
                "IA dedicada: escolhida automaticamente pelo robô identificado no WebSocket.",
                "Dedicated AI: automatically selected by the robot identified through WebSocket.",
            ))
    except Exception:
        pass
    try:
        if getattr(self, "telemetry_mode_combo", None) is not None and hasattr(self, "_telemetry_mode_options"):
            vals = list(self._telemetry_mode_options())
            self.telemetry_mode_combo.configure(values=vals)
            if getattr(self, "telemetry_mode_var", None) is not None:
                self.telemetry_mode_var.set(self._telemetry_mode_display_from_bool())
    except Exception:
        pass
    try:
        if getattr(self, "world_label", None) is not None:
            self.world_label.configure(text=_synrov_world_label(self))
    except Exception:
        pass
    try:
        if hasattr(self, "_organize_operation_checkboxes"):
            self._organize_operation_checkboxes()
    except Exception:
        pass
    try:
        if hasattr(self, "_refresh_operation_hint_text"):
            self._refresh_operation_hint_text()
    except Exception:
        pass


# Install operation text updates after frontend and voice setup.
