_orig_synrov_apply_language_google_final = SynROV._apply_language

def _synrov_apply_language_google_final_wrapper(self) -> Any:
    result = _orig_synrov_apply_language_google_final(self)
    try:
        _synrov_apply_dynamic_language_google(self)
    except Exception:
        pass
    return result


_orig_synrov_ui_tick_google_final = SynROV._ui_tick

def _synrov_ui_tick_google_final_wrapper(self) -> Any:
    result = _orig_synrov_ui_tick_google_final(self)
    try:
        ctx = self.voice_engine.context()
        if getattr(self, "audio_diag_var", None) is not None:
            dev = str(ctx.get("device_label", "") or "")
            backend = str(ctx.get("audio_backend", "off"))
            speech = str(ctx.get("speech_backend", "off"))
            diag = str(ctx.get("diagnostics", "") or ctx.get("error", "") or "")
            meter = clamp(safe_float(ctx.get("audio_meter", 0.0), 0.0) * 100.0, 0.0, 100.0)
            if self.voice_engine.running:
                msg = _synrov_pair_final(
                    self,
                    f"Áudio: {meter:.0f}% | microfone={dev} | captura={backend} | fala=Google ({speech}) | {diag}",
                    f"Audio: {meter:.0f}% | microphone={dev} | capture={backend} | speech=Google ({speech}) | {diag}",
                )
            elif diag:
                msg = _synrov_pair_final(
                    self,
                    f"Áudio parado. Último detalhe: {diag}",
                    f"Audio stopped. Last detail: {diag}",
                )
            else:
                msg = _synrov_pair_final(self, "Áudio parado. Backend: Google.", "Audio stopped. Backend: Google.")
            self.audio_diag_var.set(msg[:900])
    except Exception:
        pass
    return result


SynROV._apply_language = _synrov_apply_language_google_final_wrapper
SynROV._ui_tick = _synrov_ui_tick_google_final_wrapper


