# Sistema v1: interface original com textos e fluxo operacional consolidados
_SynROVSistemaV1Base = SynROV

class SynROV(_SynROVSistemaV1Base):
    """Sistema v1 sobre a interface Tkinter original."""

    def __init__(self, root: tk.Tk) -> None:
        super().__init__(root)
        try:
            self.root.title(self._ui_pair("SynROV AiBot — Sistema v1", "SynROV AiBot — System v1"))
        except Exception:
            pass
        try:
            self._sistema_v1_refresh_interface()
        except Exception:
            pass

    def _sistema_v1_order_tabs(self) -> None:
        # Aprendizado: dados e modelo is the primary workflow tab — always first.
        try:
            ordered = [self.tab_learning, self.tab_operation, self.tab_intents, self.tab_guide, self.tab_log]
        except Exception:
            return
        for index, child in enumerate(ordered):
            try:
                self.notebook.insert(index, child)\

            except Exception:
                pass
        try:
            self.notebook.tab(self.tab_learning, text=self._tr("learning_tab"))
            self.notebook.tab(self.tab_operation, text=self._tr("operation_tab"))
            self.notebook.tab(self.tab_intents, text=self._tr("intents_tab"))
            self.notebook.tab(self.tab_guide, text=self._tr("guide_tab"))
            self.notebook.tab(self.tab_log, text=self._tr("log_tab"))
        except Exception:
            pass
        # Select the learning tab so it opens first every time.
        try:
            self.notebook.select(self.tab_learning)
        except Exception:
            pass

    def _sistema_v1_hide_redundant_learning_buttons(self) -> None:
        for attr in (
            "btn_seed_rich_base_base_model",
            "btn_seed_rich_base_train_base_model",
            "btn_natural_base_train",
        ):
            widget = getattr(self, attr, None)
            if widget is None:
                continue
            for remover in ("pack_forget", "grid_remove", "place_forget"):
                try:
                    getattr(widget, remover)()
                except Exception:
                    pass

    def _sistema_v1_update_orchestrator_lock(self) -> None:
        try:
            orch = getattr(self, "orchestrator", None)
            if orch is not None and hasattr(orch, "set_automation_locked"):
                orch.set_automation_locked(bool(getattr(self, "safe_auto_var", tk.BooleanVar(value=False)).get()))
        except Exception:
            pass

    def _sistema_v1_refresh_interface(self) -> None:
        try:
            self.root.title(self._ui_pair("SynROV AiBot — Sistema v1", "SynROV AiBot — System v1"))
        except Exception:
            pass
        self._sistema_v1_order_tabs()
        self._sistema_v1_hide_redundant_learning_buttons()
        self._sistema_v1_update_orchestrator_lock()
        # Refresh telemetry type radio labels when language changes
        try:
            lang = self.lang.get()
            if getattr(self, "lbl_telemetry_type_cc", None) is not None:
                self.lbl_telemetry_type_cc.configure(
                    text="Telemetria:" if lang == "pt" else "Telemetry:"
                )
            if getattr(self, "radio_telem_full", None) is not None:
                self.radio_telem_full.configure(
                    text="Completa (todos os sensores)" if lang == "pt" else "Full (all sensors)"
                )
            if getattr(self, "radio_telem_filtered", None) is not None:
                self.radio_telem_filtered.configure(
                    text="Filtrada por robô (recomendado)" if lang == "pt" else "Robot-filtered (recommended)"
                )
            if getattr(self, "lbl_target_color_cc", None) is not None:
                self.lbl_target_color_cc.configure(text=self._tr("target_color"))
        except Exception:
            pass
        try:
            if getattr(self, "btn_prev_stage", None) is not None:
                self.btn_prev_stage.configure(text=self._tr("prev_stage"))
            if getattr(self, "btn_apply_stage", None) is not None:
                self.btn_apply_stage.configure(text=self._tr("apply_stage"))
            if getattr(self, "btn_next_stage", None) is not None:
                self.btn_next_stage.configure(text=self._tr("next_stage"))
        except Exception:
            pass
        try:
            if getattr(self, "chk_safe", None) is not None:
                self.chk_safe.configure(text=self._tr("safe_auto"))
        except Exception:
            pass

    def _apply_language(self) -> None:
        try:
            result = super()._apply_language()
        except Exception:
            result = None
        try:
            self._sistema_v1_refresh_interface()
        except Exception:
            pass
        # Keep color comboboxes in sync with the active language
        try:
            self._update_color_display(getattr(self.lang, "get", lambda: "pt")())
        except Exception:
            pass
        return result

    def _ui_tick(self) -> None:
        try:
            self._sistema_v1_update_orchestrator_lock()
        except Exception:
            pass
        return super()._ui_tick()


